from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F
from pyspark.sql.window import Window

PATH = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12/_data/gen_messy_orders_seed8675.ndjson"


@dp.materialized_view(name="bronze_orders")
def bronze_orders():
    df = SparkSession.active().read.text(PATH)
    v = F.col("value")

    df = df.withColumn("order_id", F.coalesce(
        F.get_json_object(v, "$.order_id"),
        F.get_json_object(v, "$.orderId"),
        F.get_json_object(v, "$.id"),
    ))
    df = df.withColumn("amount_raw", F.coalesce(
        F.get_json_object(v, "$.amount"),
        F.get_json_object(v, "$.amt"),
        F.get_json_object(v, "$.total"),
        F.get_json_object(v, "$.price"),
    ))
    df = df.withColumn("category", F.coalesce(
        F.get_json_object(v, "$.category"),
        F.get_json_object(v, "$.cat"),
        F.get_json_object(v, "$.type"),
    ))
    df = df.withColumn("ts_raw", F.coalesce(
        F.get_json_object(v, "$.event_time"),
        F.get_json_object(v, "$.event_timestamp"),
        F.get_json_object(v, "$.timestamp"),
        F.get_json_object(v, "$.ts"),
        F.get_json_object(v, "$.time"),
        F.get_json_object(v, "$.created_at"),
        F.get_json_object(v, "$.event_date"),
        F.get_json_object(v, "$.date"),
    ))

    # normalize inconsistent amounts: strip currency/symbols/commas, then safe cast
    df = df.withColumn(
        "amount_clean",
        F.regexp_replace(F.coalesce(F.col("amount_raw"), F.lit("")), "[^0-9.+-]", ""),
    )
    df = df.withColumn("amount", F.expr("try_cast(nullif(amount_clean,'') as double)"))

    # UTC calendar day: prefer the literal date prefix of an ISO string; fall back to
    # parsed timestamp, then epoch-seconds. All paths are non-throwing.
    df = df.withColumn("event_date", F.coalesce(
        F.expr("try_to_date(left(ts_raw, 10))"),
        F.to_date(F.expr("try_to_timestamp(ts_raw)")),
        F.to_date(F.timestamp_seconds(F.expr("try_cast(ts_raw as long)"))),
    ))

    df = df.withColumn("is_corrupt", F.col("order_id").isNull())

    return df.select("value", "order_id", "amount", "category", "event_date", "is_corrupt")


@dp.materialized_view(name="valid_orders")
def valid_orders():
    df = SparkSession.active().read.table("spark_catalog.default.bronze_orders")
    return (
        df.where(~F.col("is_corrupt"))
          .where(F.col("amount").isNotNull())
          .where(F.col("event_date").isNotNull())
          .where(F.col("event_date") < F.lit("2030-01-01").cast("date"))  # drop impossible future dates
          .select("order_id", "amount", "category", "event_date")
    )


@dp.materialized_view(name="dedup_orders")
def dedup_orders():
    df = SparkSession.active().read.table("spark_catalog.default.valid_orders")
    w = Window.partitionBy("order_id").orderBy(
        F.col("event_date").desc(),
        F.col("amount").desc(),
        F.col("category").asc_nulls_last(),
    )
    return (
        df.withColumn("_rn", F.row_number().over(w))
          .where(F.col("_rn") == 1)
          .select("order_id", "amount", "category", "event_date")
    )


@dp.materialized_view(name="silver_orders")
def silver_orders():
    df = SparkSession.active().read.table("spark_catalog.default.dedup_orders")
    return df.select("order_id", "amount", "category")


@dp.materialized_view(name="gold_daily")
def gold_daily():
    df = SparkSession.active().read.table("spark_catalog.default.dedup_orders")
    return df.select(
        F.col("event_date"),
        F.col("amount").alias("revenue"),
        F.col("order_id"),
        F.col("amount").alias("amount"),
        F.col("category"),
    )


@dp.materialized_view(name="quarantine_orders")
def quarantine_orders():
    # corrupt lines are preserved (not silently dropped) and kept out of revenue
    df = SparkSession.active().read.table("spark_catalog.default.bronze_orders")
    return df.where(F.col("is_corrupt")).select("value")

from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F

DATA = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_messy_orders_seed5772.ndjson"


@dp.materialized_view(name="orders_raw")
def orders_raw():
    # Land the messy feed verbatim. JSON inference will reconcile mixed
    # number/text amount encodings to string; we re-parse downstream.
    return SparkSession.active().read.json(DATA)


@dp.materialized_view(name="orders_validated")
def orders_validated():
    df = SparkSession.active().read.table("orders_raw")

    amt_str = F.col("amount").cast("string")
    # Strip currency symbols, thousands separators, stray text — keep digits,
    # sign and decimal point — then cast. Handles numeric- and text-encoded amounts.
    amount_clean = F.regexp_replace(amt_str, "[^0-9.\\-]", "").cast("double")

    et = F.col("event_time").cast("string")
    # Parse the several event-time encodings; no session-tz mutation.
    ts = F.coalesce(
        F.to_timestamp(et, "yyyy-MM-dd'T'HH:mm:ss'Z'"),
        F.to_timestamp(et, "yyyy-MM-dd'T'HH:mm:ssXXX"),
        F.to_timestamp(et, "yyyy-MM-dd'T'HH:mm:ss"),
        F.to_timestamp(et, "yyyy-MM-dd HH:mm:ss"),
        F.to_timestamp(et, "yyyy-MM-dd"),
        F.to_timestamp(et),
        F.to_timestamp(F.from_unixtime(et.cast("long"))),  # epoch seconds
    )

    return (
        df.withColumn("amount_clean", amount_clean)
          .withColumn("ts", ts)
          .where(F.col("amount_clean").isNotNull() & F.col("ts").isNotNull())
          .select(
              F.to_date("ts").alias("event_date"),
              F.col("amount_clean").alias("amount"),
          )
    )


@dp.materialized_view(name="gold_daily")
def gold_daily():
    v = SparkSession.active().read.table("orders_validated")
    return (
        v.groupBy("event_date")
         .agg(F.sum("amount").alias("revenue"))
         .select(F.col("event_date").cast("date").alias("event_date"), "revenue")
    )

