KEY = _pick(["customer_id", "customerId", "cust_id", "id"], "customer_id")
SEQ = _pick(["seq", "sequence", "seq_no", "seqno", "version", "ver",
             "event_seq", "change_seq", "lsn", "offset", "ts",
             "timestamp", "event_ts", "change_ts"], "seq")
OP  = _pick(["op", "operation", "op_type", "change_type", "event_type",
             "action", "cdc_op", "_op"], "op")


@dp.materialized_view(name="customers_cdc_raw")
def customers_cdc_raw():
    return SparkSession.active().read.json(DATA)


@dp.materialized_view(name="customers_history")
def customers_history():
    src = SparkSession.active().read.table("customers_cdc_raw")
    # Deduplicate exact replays (nightly reload) -> idempotent: one row per version.
    return (
        src.dropDuplicates([KEY, SEQ])
           .select(
               F.col(KEY).alias("customer_id"),
               F.col(SEQ).alias("version"),
               F.lower(F.col(OP).cast("string")).alias("op"),
               F.col("tier"),
               F.col("region"),
           )
    )


@dp.materialized_view(name="customers_current")
def customers_current():
    h = SparkSession.active().read.table("customers_history")
    # Most recent real state per customer, regardless of arrival jumble.
    w = Window.partitionBy("customer_id").orderBy(F.col("version").desc())
    latest = h.withColumn("_rn", F.row_number().over(w)).where(F.col("_rn") == 1)
    # A customer whose latest event is a removal is not part of current state.
    alive = latest.where(
        ~F.col("op").isin("delete", "deleted", "d", "remove", "removed", "r")
    )
    return alive.select("customer_id", "tier", "region")

