    return SparkSession.active().read.json(SRC)


@dp.materialized_view(name="customers_events")
def customers_events():
    # Idempotency: the nightly reload re-emits identical events. distinct() over
    # the full event row collapses exact replays deterministically so reprocessing
    # the same input cannot change the result.
    df = SparkSession.active().read.table("customers_cdc_raw")
    return df.distinct()


@dp.materialized_view(name="customers_history")
