from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F
from pyspark.sql.window import Window

PATH = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_customers_cdc_seed16180.ndjson"

CAT = "spark_catalog.default."


# ---- column detection (module-level: not inside a query function) -----------
def _detect_cols():
    try:
        s = SparkSession.active() or SparkSession.builder.getOrCreate()
        return set(s.read.json(PATH).columns)
    except Exception:
        return set()


_COLS = _detect_cols()


def _pick(cands, default=None):
    for c in cands:
        if c in _COLS:
            return c
    return default


ID_C   = _pick(["customer_id", "customerId", "cust_id", "id"], "customer_id")
TIER_C = _pick(["tier", "customer_tier", "tier_name"], "tier")
REG_C  = _pick(["region", "customer_region", "region_name"], "region")
OP_C   = _pick(["op", "operation", "change_type", "op_type", "action",
                "cdc_op", "_op", "change", "event_type"], None)
SEQ_C  = _pick(["seq", "sequence", "sequence_number", "seq_num", "version",
                "lsn", "offset", "change_seq", "event_seq", "_seq", "rev"], None)
TS_C   = _pick(["ts", "timestamp", "event_ts", "event_time", "event_timestamp",
                "updated_at", "change_ts", "_ts", "time"], None)
ORD_C  = SEQ_C or TS_C or "seq"

_DELETE_TOKENS = ["delete", "d", "del", "remove", "removal", "removed", "deleted"]


# ---- 1. normalized + de-duplicated source events ----------------------------
@dp.materialized_view(name="customers_cdc_clean")
def customers_cdc_clean():
    s = SparkSession.active()
    df = s.read.json(PATH)
    cols = [
        F.col(ID_C).alias("customer_id"),
        F.col(TIER_C).alias("tier"),
        F.col(REG_C).alias("region"),
    ]
    if OP_C:
        cols.append(F.lower(F.trim(F.col(OP_C).cast("string"))).alias("op"))
    else:
        cols.append(F.lit("upsert").alias("op"))
    cols.append(F.col(ORD_C).alias("seq"))
    # full-row dedup => re-delivered (reloaded) identical events collapse to one
    return df.select(*cols).dropDuplicates()


# ---- 2. full change-history: one row per surviving version ------------------
@dp.materialized_view(name="customers_history")
def customers_history():
    s = SparkSession.active()
    e = s.read.table(CAT + "customers_cdc_clean")
    # deterministic ordering across the jumbled feed
    w = Window.partitionBy("customer_id").orderBy(
        F.col("seq").asc(), F.col("op").asc(),
        F.col("tier").asc_nulls_last(), F.col("region").asc_nulls_last(),
    )
    return (
        e.withColumn("version", F.row_number().over(w))
         .select("customer_id", "version", "tier", "region", "op", "seq")
    )


# ---- 3. current state: latest non-delete version, derived FROM history ------
@dp.materialized_view(name="customers_current")
def customers_current():
    s = SparkSession.active()
    h = s.read.table(CAT + "customers_history")
    w = Window.partitionBy("customer_id").orderBy(F.col("version").desc())
    latest = h.withColumn("rn", F.row_number().over(w)).where(F.col("rn") == 1)
    return (
        latest.where(~F.col("op").isin(*_DELETE_TOKENS))
              .select("customer_id", "tier", "region")
    )

