# ---- Bronze: raw CDC events as emitted (jumbled order, possible replays) ----
@dp.materialized_view(name="customers_cdc_raw")
def customers_cdc_raw():
    spark = SparkSession.active()
    return spark.read.json(DATA)

# ---- History: one row per real version, idempotent under replay ----
# A "version" is uniquely identified by (customer_id, seq). Replaying the same
# events yields identical (customer_id, seq) tuples, so de-duplication makes the
# result stable. We keep every op (incl. removals) so history is the full log.
@dp.materialized_view(name="customers_history")
def customers_history():
    spark = SparkSession.active()
    df = spark.read.table("customers_cdc_raw")
    return df.dropDuplicates(["customer_id", "seq"])

# ---- Current: latest real state per customer, ordered by seq (not arrival) ----
# Picking the max-seq version per customer fixes the "live screen vs audit
# export disagree" symptom (naive last-write-wins on arrival order was wrong).
# If the latest version is a removal, the customer is not currently present.
@dp.materialized_view(name="customers_current")
def customers_current():
    spark = SparkSession.active()
    hist = spark.read.table("customers_history")
    w = Window.partitionBy("customer_id").orderBy(F.col("seq").desc())
    latest = hist.withColumn("_rn", F.row_number().over(w)).filter(F.col("_rn") == 1)
    op = F.lower(F.col("op").cast("string"))
    alive = latest.filter(~op.isin("delete", "remove", "d"))
    return alive.select("customer_id", "tier", "region")

import os
import re
from pyspark.sql import SparkSession, functions as F, types as T


def get_spark():
    spark = (
        SparkSession.builder
        .appName("p3_windows")
        .getOrCreate()
    )
    # Bucket by real wall-clock UTC hours / UTC calendar day.
    spark.conf.set("spark.sql.session.timeZone", "UTC")
    return spark


# ---------------------------------------------------------------------------
# Robust parsers (return NULL instead of throwing -> no CAST_INVALID_INPUT)
# ---------------------------------------------------------------------------
@F.udf(T.LongType())
def to_epoch_seconds(v):
    """Normalize a heterogeneous timestamp value to UTC epoch seconds."""
    if v is None:
        return None
    s = str(v).strip()
    if not s:
        return None

    # Numeric epoch (seconds / millis / micros)
    try:
        f = float(s)
        a = abs(f)
        if a >= 1e14:        # microseconds
            f = f / 1e6
        elif a >= 1e11:      # milliseconds
            f = f / 1e3
        # else: already seconds
        return int(f)
    except (ValueError, OverflowError):
        pass

    # ISO-8601 / common datetime strings
    from datetime import datetime, timezone
    t = s.replace("Z", "+00:00").replace("z", "+00:00")
    dt = None
    try:
        dt = datetime.fromisoformat(t)
    except ValueError:
        for fmt in (
            "%Y-%m-%dT%H:%M:%S.%f",
            "%Y-%m-%dT%H:%M:%S",
            "%Y-%m-%d %H:%M:%S.%f",
            "%Y-%m-%d %H:%M:%S",
            "%Y/%m/%d %H:%M:%S",
            "%Y-%m-%d %H:%M",
            "%Y-%m-%d",
            "%Y/%m/%d",
            "%m/%d/%Y %H:%M:%S",
            "%m/%d/%Y",
        ):
            try:
                dt = datetime.strptime(s, fmt)
                break
            except ValueError:
                continue
    if dt is None:
        return None
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    try:
        return int(dt.timestamp())
    except (ValueError, OverflowError):
        return None


@F.udf(T.DoubleType())
def to_amount(v):
    """Normalize a heterogeneous monetary value to a double."""
    if v is None:
        return None
    if isinstance(v, bool):
        return None
    if isinstance(v, (int, float)):
        return float(v)
    s = str(v).strip()
    if not s:
        return None
    neg = False
    if s.startswith("(") and s.endswith(")"):
        neg = True
        s = s[1:-1]
    if s.endswith("-"):
        neg = True
        s = s[:-1]
    if s.startswith("-"):
        neg = True
        s = s[1:]
    # strip currency symbols, thousands separators, etc.
    s = re.sub(r"[^0-9.]", "", s)
    if s in ("", ".") or s.count(".") > 1:
        # handle accidental multiple dots by keeping first
        parts = s.split(".")
        if len(parts) > 1:
            s = parts[0] + "." + "".join(parts[1:])
        else:
            return None
    try:
        f = float(s)
    except ValueError:
        return None
    return -f if neg else f


def pick_col(cols, candidates):
    lower = {c.lower(): c for c in cols}
    for cand in candidates:
        if cand in lower:
            return lower[cand]
    return None


def main():
    spark = get_spark()

    default_input = (
        "/home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/"
        ".work.powered.AB.n12.part2/_data/gen_messy_orders_seed11235.ndjson"
    )
    input_path = os.environ.get("AGENT_INPUT_PATH", default_input)
    output_path = os.environ.get("AGENT_OUTPUT_PATH")
    output_table = os.environ.get("AGENT_OUTPUT_TABLE")

    raw = spark.read.json(input_path)
    cols = raw.columns

    ts_col = pick_col(cols, [
        "event_time", "event_ts", "event_timestamp", "order_time", "order_ts",
        "created_at", "timestamp", "ts", "time", "order_date", "datetime",
    ])
    amt_col = pick_col(cols, [
        "revenue", "amount", "price", "total", "order_total", "amount_usd",
        "gross", "gross_amount", "value", "sales", "net",
    ])
    cat_col = pick_col(cols, [
        "category", "cat", "product_category", "segment", "dept", "department",
    ])
    id_col = pick_col(cols, [
        "order_id", "id", "event_id", "uuid", "txn_id", "transaction_id",
    ])

    if ts_col is None or amt_col is None:
        raise ValueError(
            f"Could not locate required columns. ts={ts_col}, amt={amt_col}, "
            f"available={cols}"
        )

    df = raw.withColumn("_epoch", to_epoch_seconds(F.col(ts_col)))
    df = df.withColumn("_amount", to_amount(F.col(amt_col)))

    if cat_col is not None:
        df = df.withColumn("_category",
                           F.coalesce(F.col(cat_col).cast("string"), F.lit("UNKNOWN")))
    else:
        df = df.withColumn("_category", F.lit("UNKNOWN"))

    # Drop rows we cannot place on the wall clock or value.
    df = df.filter(F.col("_epoch").isNotNull() & F.col("_amount").isNotNull())

    # Idempotency: reprocessing identical input must not change the result.
    if id_col is not None:
        df = df.dropDuplicates([id_col])
    else:
        df = df.dropDuplicates()

    # Real wall-clock UTC timestamp + derived calendar grains.
    df = df.withColumn("_event_ts", F.timestamp_seconds(F.col("_epoch")))
    df = df.withColumn("event_date", F.to_date(F.col("_event_ts")))
    df = df.withColumn("event_hour", F.date_trunc("hour", F.col("_event_ts")))

    # Hourly revenue breakdown per category (intermediate, ties out by construction).
    gold_hourly = (
        df.groupBy("event_hour", "_category")
          .agg(F.sum("_amount").alias("revenue"))
          .withColumnRenamed("_category", "category")
          .orderBy("event_hour", "category")
    )
    gold_hourly.createOrReplaceTempView("gold_hourly")

    # Daily revenue (contract grain) -- equals the rollup of the hourly buckets.
    gold_daily = (
        df.groupBy("event_date")
          .agg(F.sum("_amount").alias("revenue"))
          .select(
              F.col("event_date").cast("date").alias("event_date"),
              F.col("revenue").cast("double").alias("revenue"),
          )
          .orderBy("event_date")
    )
    gold_daily.createOrReplaceTempView("gold_daily")

    if output_path:
        gold_daily.write.mode("overwrite").parquet(output_path)
    elif output_table:
        gold_daily.write.mode("overwrite").saveAsTable(output_table)
    else:
        raise ValueError("No output destination provided (AGENT_OUTPUT_PATH / AGENT_OUTPUT_TABLE).")

    print("Run is COMPLETED")
    spark.stop()


