DATA = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_messy_orders_seed9001.ndjson"


# ---- schema peek (driver-only, outside any pipeline query fn) ----
def _peek():
    try:
        return {f.name for f in SparkSession.active().read.json(DATA).schema.fields}
    except Exception:
        return set()


_COLS = _peek()


def _pick(cands, default):
    for c in cands:
        if c in _COLS:
            return c
    return default


TS_COL = _pick(["ts", "event_time", "event_ts", "order_ts", "timestamp",
                "time", "created_at", "order_time"], "ts")
REV_COL = _pick(["amount", "revenue", "price", "total", "value",
                 "amount_usd", "gross", "sales"], "amount")
CAT_COL = _pick(["category", "cat", "product_category", "segment"], "category")
ID_COL = _pick(["order_id", "id", "event_id", "uuid", "txn_id"], None)


# ---- timezone-independent instant -> epoch seconds ----
def epoch_seconds(col):
    s = F.trim(col.cast("string"))
    is_num = s.rlike(r"^-?[0-9]+(\.[0-9]+)?$")
    num = s.cast("double")
    # disambiguate seconds vs milliseconds by magnitude
    epoch_num = F.when(F.abs(num) > F.lit(1e12), num / F.lit(1000.0)).otherwise(num)
    # ISO / wall-clock string: normalize space->T, force UTC when no zone present,
    # then read the fixed instant (cast timestamp->long = epoch secs, tz-agnostic).
    s2 = F.regexp_replace(s, " ", "T")
    has_zone = s2.rlike(r"(Z|[+-][0-9]{2}:?[0-9]{2})$")
    norm = F.when(has_zone, s2).otherwise(F.concat(s2, F.lit("Z")))
    epoch_iso = F.to_timestamp(norm).cast("long").cast("double")
    return F.when(is_num, epoch_num).otherwise(epoch_iso)


def revenue_expr():
    direct = F.col(REV_COL).cast("double")
    cleaned = F.regexp_replace(F.col(REV_COL).cast("string"), r"[^0-9.\-]", "").cast("double")
    return F.coalesce(direct, cleaned)


@dp.materialized_view(name="orders_clean")
def orders_clean():
    df = SparkSession.active().read.json(DATA)
    if ID_COL:
        df = df.dropDuplicates([ID_COL])
    ev = epoch_seconds(F.col(TS_COL))
    day = F.floor(ev / F.lit(86400.0)).cast("int")
    hour_start = (F.floor(ev / F.lit(3600.0)) * F.lit(3600)).cast("long")
    return (
        df.select(
            ev.alias("_ev"),
            F.date_from_unix_date(day).alias("event_date"),
            F.timestamp_seconds(hour_start).alias("event_hour"),
            F.coalesce(F.col(CAT_COL).cast("string"), F.lit("UNKNOWN")).alias("category"),
            revenue_expr().alias("revenue"),
        )
        .where(F.col("_ev").isNotNull())
        .drop("_ev")
    )


@dp.materialized_view(name="gold_hourly")
def gold_hourly():
    df = SparkSession.active().read.table("spark_catalog.default.orders_clean")
    return (
        df.groupBy("event_hour", "category")
        .agg(F.sum("revenue").alias("revenue"))
    )


@dp.materialized_view(name="gold_daily")
def gold_daily():
    # roll up from the SAME cleaned grain as the hourly breakdown,
    # so hourly buckets tie out exactly to the daily revenue.
    df = SparkSession.active().read.table("spark_catalog.default.orders_clean")
    return (
        df.groupBy("event_date")
        .agg(F.sum("revenue").alias("revenue"))
    )

