# Explicit schema => every referenced column resolves (absent ones become null),
# which eliminates UNRESOLVED_COLUMN and keeps messy/array/typed values from
# blowing up schema inference. Numeric-ish fields read as strings, cleaned below.
SCHEMA = StructType([
    StructField("order_id", StringType()),
    StructField("merchant_id", StringType()),
    StructField("merchant", StringType()),
    StructField("merchant_name", StringType()),
    StructField("category", StringType()),
    StructField("amount", StringType()),
    StructField("price", StringType()),
    StructField("value", StringType()),
    StructField("total", StringType()),
    StructField("revenue", StringType()),
])


def _num(col):
    # Strip currency symbols/commas/whitespace, then cast. Bad/empty -> null.
    cleaned = F.regexp_replace(F.coalesce(F.col(col).cast("string"), F.lit("")), r"[^0-9.\-]", "")
    return F.when(cleaned == "", F.lit(None)).otherwise(cleaned.cast("double"))


def _revenue():
    # First non-null numeric across candidate amount fields; default 0.0 so a
    # messy/missing amount never drops the row from the total.
    return F.coalesce(_num("amount"), _num("revenue"), _num("price"),
                      _num("value"), _num("total"), F.lit(0.0))


def _merchant():
    return F.coalesce(F.col("merchant_id"), F.col("merchant"),
                      F.col("merchant_name"), F.lit("unknown"))


def _read():
    return SparkSession.active().read.schema(SCHEMA).json(DATA)


@dp.materialized_view(name="merchant_totals")
def merchant_totals():
    # Per-merchant total over EVERY row (no category filter/explode) so merchants
    # never see missing sales. Contract grain: revenue per merchant.
    df = (_read()
          .withColumn("merchant", _merchant())
          .withColumn("revenue", _revenue()))
    return df.groupBy("merchant").agg(F.sum("revenue").alias("revenue"))


@dp.materialized_view(name="category_totals")
def category_totals():
    # Same feed, bucketing null categories into 'unknown' so this view's rows
    # reconcile to the merchant totals instead of quietly dropping sales.
    df = (_read()
          .withColumn("category", F.coalesce(F.col("category"), F.lit("unknown")))
          .withColumn("revenue", _revenue()))
    return df.groupBy("category").agg(F.sum("revenue").alias("revenue"))

