# --- column detection (module import time only; never inside a query fn) ---
_ID_CANDS = ["customer_id", "customerid", "cust_id", "custid", "id",
             "customer", "customerkey", "customer_key"]
_SEQ_CANDS = ["seq", "sequence", "sequence_num", "seq_num", "seqnum", "version",
              "ts", "timestamp", "event_ts", "event_time", "event_timestamp",
              "change_ts", "updated_at", "update_ts", "offset", "lsn",
              "_seq", "__seq", "commit_ts", "cdc_ts", "op_ts"]
_OP_CANDS = ["op", "operation", "_op", "__op", "change_type", "cdc_op",
             "event_type", "action", "optype", "op_type",
             "__deleted", "deleted", "is_deleted"]
_TIER_CANDS = ["tier", "customer_tier", "tier_name", "segment_tier"]
_REGION_CANDS = ["region", "customer_region", "region_name", "geo_region"]


def _detect():
    try:
        spark = SparkSession.active()
        if spark is None:
            return {}
        return {c.lower(): c for c in spark.read.json(DATA).columns}
    except Exception:
        return {}


_COLS = _detect()


def _pick(cands, default):
    for c in cands:
        if c in _COLS:
            return _COLS[c]
    return default


_ID = _pick(_ID_CANDS, "customer_id")
_SEQ = _pick(_SEQ_CANDS, None)
_OP = _pick(_OP_CANDS, "op")
_TIER = _pick(_TIER_CANDS, "tier")
_REGION = _pick(_REGION_CANDS, "region")

_DELETE_VALS = ["delete", "d", "del", "remove", "removed", "r", "true", "1"]


@dp.materialized_view(name="customers_cdc_raw")
def customers_cdc_raw():
    # lazy batch relation -> materialized_view (NOT @dp.table)
    return SparkSession.active().read.json(DATA)


@dp.materialized_view(name="customer_segments")
def customer_segments():
    df = SparkSession.active().read.table("spark_catalog.default.customers_cdc_raw")

    # establish an ordering key to recover each customer's CURRENT state
    if _SEQ is not None:
        ordered = df.withColumn("_ord", F.col(_SEQ).cast("string"))
    else:
        # deterministic-enough fallback: file/read order
        ordered = df.withColumn("_ord", F.monotonically_increasing_id().cast("string"))

    w = Window.partitionBy(F.col(_ID)).orderBy(F.col("_ord").desc())
    latest = (
        ordered
        .withColumn("_rn", F.row_number().over(w))
        .where(F.col("_rn") == 1)
    )

    # drop customers whose latest CDC event is a removal
    op_norm = F.lower(F.trim(F.coalesce(F.col(_OP).cast("string"), F.lit(""))))
    current = latest.where(~op_norm.isin(_DELETE_VALS))

    return (
        current
        .groupBy(F.col(_TIER).alias("tier"), F.col(_REGION).alias("region"))
        .agg(F.count(F.lit(1)).alias("n"))
    )

