from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F

DATA = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_messy_orders_seed27182.ndjson"

# ---- candidate field names (event time = when the order ACTUALLY occurred) ----
_EVENT = ["event_time", "event_ts", "event_timestamp", "occurred_at", "occurred",
          "order_time", "order_ts", "sale_time", "client_time", "created_at",
          "created", "timestamp", "ts"]
# arrival/ingest fields are deliberately NOT used for dating (late-data symptom)
_AMOUNT = ["amount", "revenue", "price", "total", "value", "amount_usd",
           "sale_amount", "order_total", "gross", "net", "sales"]
_ID = ["order_id", "id", "oid", "order", "uuid", "event_id", "order_uuid",
       "txn_id", "transaction_id"]


def _discover():
    # profile the messy feed at import time (top-level => not a query-fn action)
    try:
        cols = SparkSession.active().read.json(DATA).columns
        return {c.lower(): c for c in cols}
    except Exception:
        return {}


_M = _discover()


def _pick(cands, default=None):
    for c in cands:
        if c in _M:
            return _M[c]
    return default


EVENT_COL = _pick(_EVENT, "event_time")
AMOUNT_COL = _pick(_AMOUNT, "amount")
ID_COL = _pick(_ID, None)


def _parse_ts(colname):
    s = F.col(colname).cast("string")
    iso = F.to_timestamp(s)                      # ISO / offset strings -> instant
    num = s.cast("double")                        # numeric epoch fallback
    epoch = F.when(num > F.lit(1e11), num / F.lit(1000.0)).otherwise(num)  # ms->s
    from_num = F.timestamp_seconds(epoch.cast("long"))
    return F.coalesce(iso, from_num)


def _utc_event_date(colname):
    # epoch seconds is an absolute instant (tz-independent); derive UTC calendar day
    epoch_sec = _parse_ts(colname).cast("long")
    days = F.floor(epoch_sec / F.lit(86400)).cast("int")
    return F.date_add(F.to_date(F.lit("1970-01-01")), days)


def _amount(colname):
    cleaned = F.regexp_replace(F.col(colname).cast("string"), r"[^0-9.\-]", "")
    return cleaned.cast("double")


@dp.materialized_view(name="bronze_orders")
def bronze_orders():
    return SparkSession.active().read.json(DATA)


@dp.materialized_view(name="gold_daily")
def gold_daily():
    df = SparkSession.active().read.table("bronze_orders")
    df = (df
          .withColumn("event_date", _utc_event_date(EVENT_COL))
          .withColumn("_amt", _amount(AMOUNT_COL)))

    # idempotency: collapse late-arriving duplicate emissions of the same order
    if ID_COL:
        df = df.dropDuplicates([ID_COL])
    else:
        df = df.dropDuplicates()

    df = df.where(F.col("event_date").isNotNull() & F.col("_amt").isNotNull())

    return (df.groupBy("event_date")
              .agg(F.sum("_amt").alias("revenue")))

