DATA = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_payments_seed42.ndjson"

# ---- discover real column names at import time (safe: not inside a query fn) ----
def _discover():
    try:
        s = SparkSession.active()
        if s is not None:
            return set(s.read.json(DATA).columns)
    except Exception:
        pass
    return set()

_COLS = _discover()

def _pick(cands, contains=(), default=None):
    for c in cands:
        if c in _COLS:
            return c
    for c in sorted(_COLS):
        lc = c.lower()
        if any(k in lc for k in contains):
            return c
    return default

AMOUNT    = _pick(["amount", "value", "amt", "payment_amount", "minor_amount"],
                  contains=["amount", "amt", "value"], default="amount")
CURRENCY  = _pick(["currency", "ccy", "currency_code", "cur", "payment_currency"],
                  contains=["curr", "ccy"], default="currency")
TS        = _pick(["occurred_at", "event_time", "event_timestamp", "timestamp", "ts",
                   "created_at", "time", "paid_at"],
                  contains=["occur", "_at", "stamp", "time", "ts"], default="occurred_at")
RATE      = _pick(["rate", "usd_rate", "fx_rate", "rate_to_usd", "usd_per_unit",
                   "exchange_rate", "conversion_rate"],
                  contains=["rate", "_fx"], default=None)
RATE_DATE = _pick(["rate_date", "fx_date", "as_of", "as_of_date", "quote_date",
                   "effective_date"], contains=[], default=None)


def _to_utc_date(colname):
    c = F.col(colname)
    ts = F.coalesce(
        F.to_timestamp(c.cast("string")),
        F.timestamp_seconds(c.cast("long")),
    )
    # naive-UTC instant -> UTC calendar day
    return F.to_date(ts)


@dp.materialized_view(name="payments_norm")
def payments_norm():
    df = SparkSession.active().read.json(DATA)
    df = df.where(F.col(AMOUNT).isNotNull())
    return df.select(
        F.upper(F.trim(F.col(CURRENCY).cast("string"))).alias("currency"),
        F.col(AMOUNT).cast("double").alias("amount"),
        _to_utc_date(TS).alias("settlement_date"),
    )


@dp.materialized_view(name="fx_rates")
def fx_rates():
    df = SparkSession.active().read.json(DATA)
    if RATE is None:
        return (df.where(F.lit(False))
                  .select(
                      F.lit(None).cast("string").alias("currency"),
                      F.lit(None).cast("date").alias("rate_date"),
                      F.lit(None).cast("double").alias("rate"),
                  ))
    if RATE_DATE is None:
        rate_date_expr = _to_utc_date(TS)
    else:
        rate_date_expr = F.coalesce(
            F.to_date(F.col(RATE_DATE).cast("string")),
            _to_utc_date(TS),
        )
    r = (df.where(F.col(RATE).isNotNull())
           .select(
               F.upper(F.trim(F.col(CURRENCY).cast("string"))).alias("currency"),
               rate_date_expr.alias("rate_date"),
               F.col(RATE).cast("double").alias("rate"),
           ))
    # one authoritative rate per (currency, day)
    return r.groupBy("currency", "rate_date").agg(F.max("rate").alias("rate"))


@dp.materialized_view(name="fx_ccy")
def fx_ccy():
    # per-currency fallback so a recognized currency with a missing day-rate
    # is never dropped (we must lose none of the value).
    rates = SparkSession.active().read.table("fx_rates")
    return rates.groupBy("currency").agg(F.avg("rate").alias("ccy_rate"))


@dp.materialized_view(name="usd_daily")
def usd_daily():
    s = SparkSession.active()
    pay = s.read.table("payments_norm").alias("p")
    day = s.read.table("fx_rates").alias("d")
    ccy = s.read.table("fx_ccy").alias("c")

    j = (pay.join(
            day,
            (F.col("p.currency") == F.col("d.currency"))
            & (F.col("p.settlement_date") == F.col("d.rate_date")),
            "left")
         .join(
            ccy,
            F.col("p.currency") == F.col("c.currency"),
            "left"))

    eff_rate = F.coalesce(
        F.col("d.rate"),                                   # exact day rate
        F.col("c.ccy_rate"),                               # recognized-currency fallback
        F.when(F.col("p.currency") == "USD", F.lit(1.0)),  # USD passthrough
    )

    res = (j.withColumn("eff_rate", eff_rate)
            .where(F.col("eff_rate").isNotNull())          # set aside unrecognized currencies
            .withColumn("usd_amount", F.col("p.amount") * F.col("eff_rate")))

    return (res.groupBy(F.col("p.settlement_date").alias("settlement_date"))
               .agg(F.sum("usd_amount").alias("usd_total")))

