DATA = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_messy_orders_seed42.ndjson"

# Candidate field names (messy feed; we don't control emission).
REV = ["revenue", "amount", "total", "gross", "price", "order_revenue",
       "order_total", "value", "order_amount", "sales", "net", "subtotal"]
MID = ["merchant_id", "merchantId", "merchant", "mid", "merchant_key",
       "seller_id", "merchant_uuid", "store_id"]

# Explicit schema => no inference job, and every referenced column is defined
# (absent JSON keys resolve to NULL rather than UNRESOLVED_COLUMN).
SCHEMA = StructType([StructField(c, StringType(), True) for c in (REV + MID)])


@dp.materialized_view(name="orders_raw")
def orders_raw():
    spark = SparkSession.active()
    df = spark.read.schema(SCHEMA).json(DATA)
    revenue = F.coalesce(*[F.col(c).cast("double") for c in REV])
    merchant = F.coalesce(*[F.col(c).cast("string") for c in MID])
    return df.select(
        revenue.alias("__revenue"),
        merchant.alias("__merchant_id"),
    )


@dp.materialized_view(name="merchant_directory")
def merchant_directory():
    spark = SparkSession.active()
    o = spark.read.table("spark_catalog.default.orders_raw")
    # One row per merchant => left join cannot fan out revenue.
    return o.groupBy("__merchant_id").count().select("__merchant_id")


@dp.materialized_view(name="enriched_orders")
def enriched_orders():
    spark = SparkSession.active()
    o = spark.read.table("spark_catalog.default.orders_raw")
    d = spark.read.table("spark_catalog.default.merchant_directory")
    # LEFT join: every order survives, incl. merchants not yet in directory.
    return o.join(d, on="__merchant_id", how="left")


@dp.materialized_view(name="enriched_totals")
