from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F, types as T

DATA = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_messy_orders_seed8675.ndjson"

# Explicit string schema over a broad set of candidate field names.
# Every column is guaranteed to exist (null if absent in the data), which
# eliminates UNRESOLVED_COLUMN, and JSON numeric tokens read cleanly as strings.
def _schema():
    s = T.StringType()
    names = [
        "order_id", "id", "order",
        "merchant_id", "merchant", "merchant_key",
        "revenue", "amount", "total", "price", "value", "sales",
        "merchant_name", "name",
        "merchant_category", "category", "segment", "region",
    ]
    return T.StructType([T.StructField(n, s) for n in names])


def _rev_str():
    return F.coalesce(
        F.col("revenue"), F.col("amount"), F.col("total"),
        F.col("price"), F.col("value"), F.col("sales"),
    )


def _mkey():
    return F.coalesce(F.col("merchant_id"), F.col("merchant"), F.col("merchant_key"))


@dp.materialized_view(name="src_records")
def src_records():
    return SparkSession.active().read.schema(_schema()).json(DATA)


@dp.materialized_view(name="orders")
def orders():
    df = SparkSession.active().read.table("spark_catalog.default.src_records")
    rev_str = _rev_str()
    rev_clean = F.regexp_replace(rev_str.cast("string"), r"[^0-9.\-]", "")
    rev = F.coalesce(
        F.when(rev_clean == "", None).otherwise(rev_clean).cast("double"),
        F.lit(0.0),
    )
    # An order is any record carrying a monetary value (defines the raw total).
    return (
        df.where(rev_str.isNotNull())
          .select(_mkey().alias("merchant_key"), rev.alias("revenue"))
    )


@dp.materialized_view(name="merchant_dir")
def merchant_dir():
    df = SparkSession.active().read.table("spark_catalog.default.src_records")
    mname = F.coalesce(F.col("merchant_name"), F.col("name"))
    mcat = F.coalesce(F.col("merchant_category"), F.col("category"), F.col("segment"))
    # Directory = records that carry merchant attributes, deduped by key so the
    # left join cannot fan out (which would break the tie-to-source invariant).
    return (
        df.where(mname.isNotNull())
          .select(_mkey().alias("merchant_key"),
                  mname.alias("merchant_name"),
                  mcat.alias("merchant_category"))
          .groupBy("merchant_key")
          .agg(F.first("merchant_name", True).alias("merchant_name"),
               F.first("merchant_category", True).alias("merchant_category"))
    )


@dp.materialized_view(name="enriched_orders")
def enriched_orders():
    o = SparkSession.active().read.table("spark_catalog.default.orders")
    d = SparkSession.active().read.table("spark_catalog.default.merchant_dir")
    # LEFT join: every order survives, including merchants not yet in the directory.
