    return o.join(d, on="merchant_key", how="left")


@dp.materialized_view(name="enriched_totals")
def enriched_totals():
    e = SparkSession.active().read.table("spark_catalog.default.enriched_orders")
    return e.agg(F.sum("revenue").alias("revenue"))

