from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F
from pyspark.sql.window import Window

DATA_PATH = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_customers_cdc_seed27182.ndjson"


# ---- schema detection at import time (analysis allowed OUTSIDE query fns) ----
def _detect_columns():
    try:
        s = SparkSession.active()
        if s is None:
            return []
        return list(s.read.json(DATA_PATH).columns)
    except Exception:
        return []


_COLS = _detect_columns()


def _present(col):
    if col is None:
        return False
    if not _COLS:                      # detection failed -> trust chosen default
        return True
    low = {c.lower() for c in _COLS}
    return col in _COLS or col.lower() in low


def _pick(cands, default):
    low = {c.lower(): c for c in _COLS}
    for c in cands:
        if c in _COLS:
            return c
    for c in cands:
        if c.lower() in low:
            return low[c.lower()]
    return default


ID_COL = _pick(["customer_id", "cust_id", "customerId", "customerid", "id"], "customer_id")
TIER_COL = _pick(["tier", "customer_tier", "tier_name", "plan", "level"], "tier")
REGION_COL = _pick(["region", "customer_region", "region_name", "geo", "area"], "region")
TS_COL = _pick(
    ["event_ts", "event_time", "event_timestamp", "ts", "timestamp", "change_ts",
     "changed_at", "updated_at", "op_ts", "commit_ts", "modified_at",
     "effective_ts", "valid_from", "effective_from", "_ts"],
    "event_ts",
)
SEQ_COL = _pick(
    ["seq", "sequence", "seq_num", "seqno", "offset", "lsn", "version",
     "change_seq", "commit_seq", "_seq", "event_id"],
    None,
)


# ---- 1. normalize the raw CDC feed ------------------------------------------
@dp.materialized_view(name="customers_cdc_raw")
def customers_cdc_raw():
    s = SparkSession.active()
    df = s.read.json(DATA_PATH)
    return df.select(
        F.col(ID_COL).cast("string").alias("customer_id"),
        (F.col(TIER_COL) if _present(TIER_COL) else F.lit(None)).cast("string").alias("tier"),
        (F.col(REGION_COL) if _present(REGION_COL) else F.lit(None)).cast("string").alias("region"),
        F.coalesce(
            F.to_timestamp(F.col(TS_COL)),
            F.to_timestamp(F.col(TS_COL).cast("string")),
        ).alias("event_ts"),
        (F.col(SEQ_COL) if (SEQ_COL and _present(SEQ_COL)) else F.lit(None)).cast("long").alias("seq"),
    )


# ---- 2. build SCD2 versioned history ----------------------------------------
@dp.materialized_view(name="customers_history")
def customers_history():
    s = SparkSession.active()
    df = s.read.table("customers_cdc_raw").where(
        F.col("customer_id").isNotNull() & F.col("event_ts").isNotNull()
    )

    # a) resolve contradictions at the SAME instant: keep one deterministic row
    w_instant = Window.partitionBy("customer_id", "event_ts").orderBy(
        F.col("seq").desc_nulls_last(),
        F.col("tier").desc_nulls_last(),
        F.col("region").desc_nulls_last(),
    )
    one_per_instant = (
        df.withColumn("_rn", F.row_number().over(w_instant))
          .where(F.col("_rn") == 1)
          .drop("_rn")
    )

    # b) collapse consecutive versions with identical (tier, region)
    w_ord = Window.partitionBy("customer_id").orderBy(
        F.col("event_ts").asc(),
        F.col("seq").asc_nulls_last(),
    )
    tagged = (
        one_per_instant
        .withColumn("_rn", F.row_number().over(w_ord))
        .withColumn("_pt", F.lag("tier").over(w_ord))
        .withColumn("_pr", F.lag("region").over(w_ord))
    )
    changes = tagged.where(
        (F.col("_rn") == 1)
        | (~(F.col("tier").eqNullSafe(F.col("_pt"))
             & F.col("region").eqNullSafe(F.col("_pr"))))
    ).select("customer_id", "tier", "region", "event_ts")

    # c) stamp non-overlapping validity periods (event_ts unique per customer now)
    w_v = Window.partitionBy("customer_id").orderBy(F.col("event_ts").asc())
    nxt = F.lead("event_ts").over(w_v)
    return (
        changes
        .withColumn("valid_from", F.col("event_ts"))
        .withColumn("valid_to", nxt)
        .withColumn("is_current", nxt.isNull())
        .select("customer_id", "tier", "region", "valid_from", "valid_to", "is_current")
    )


# ---- 3. current-state table (latest real change per customer) ----------------
@dp.materialized_view(name="customers_current")
def customers_current():
    s = SparkSession.active()
    h = s.read.table("customers_history").where(F.col("is_current"))
    return h.select("customer_id", "tier", "region")

"""
p11_schema_evolution — tolerant ingest of an evolving `orders` NDJSON feed.

The upstream `orders` payload changed shape:
  * some records are missing fields  -> sensible defaults
  * `amount` used to be a single number, now sometimes arrives as a list of
    line items -> revenue must sum correctly across BOTH shapes.

Strategy: Spark's JSON inferrer cannot reconcile `amount` being sometimes a
number and sometimes an array within one column, so we ingest the feed as raw
text and parse each line defensively in Python. This is fully deterministic:
reprocessing the same input yields the same result.

Output contract: gold_daily(event_date DATE [UTC calendar day], revenue)
"""

