)

# Candidate keys for the event timestamp / date, in priority order.
DATE_KEYS = [
    "event_date", "event_time", "event_ts", "timestamp", "ts",
    "created_at", "order_date", "order_ts", "date", "time", "occurred_at",
]

# Candidate keys for the monetary amount at the record level.
AMOUNT_KEYS = ["amount", "amounts", "line_items", "items", "total", "revenue"]


# --------------------------------------------------------------------------- #
# Pure-python defensive parsing helpers
# --------------------------------------------------------------------------- #
def _to_number(v):
    """Coerce a scalar to float, or None if not numeric."""
    if v is None:
        return None
    if isinstance(v, bool):  # guard: bool is subclass of int
        return None
    if isinstance(v, (int, float)):
        return float(v)
    if isinstance(v, str):
        s = v.strip().replace(",", "")
        # strip a leading currency symbol if present
        if s and s[0] in "$€£":
            s = s[1:].strip()
        try:
            return float(s)
        except ValueError:
            return None
    return None


def _line_item_value(item):
    """Value of a single line item (number, string, or dict)."""
    n = _to_number(item)
    if n is not None:
        return n
    if isinstance(item, dict):
        # price * quantity when both present
        qty = None
        for qk in ("quantity", "qty", "count", "units"):
            if qk in item:
                qty = _to_number(item.get(qk))
                if qty is not None:
                    break
        price = None
        for pk in ("price", "unit_price", "unitPrice", "amount", "value", "cost"):
            if pk in item:
                price = _to_number(item.get(pk))
                if price is not None:
                    break
        if price is not None and qty is not None:
            return price * qty
        # explicit line total wins if no price/qty pair
        for tk in ("total", "line_total", "subtotal", "amount", "value", "price"):
            if tk in item:
                t = _to_number(item.get(tk))
                if t is not None:
                    return t
    return 0.0


def _amount_value(amount):
    """Revenue contribution of the `amount` field across both shapes."""
    if amount is None:
        return 0.0
    n = _to_number(amount)
    if n is not None:                       # old shape: single number/string
        return n
    if isinstance(amount, list):            # new shape: list of line items
        return float(sum(_line_item_value(it) for it in amount))
    if isinstance(amount, dict):            # single line-item object
        return _line_item_value(amount)
    return 0.0


def _extract_amount(rec):
    for k in AMOUNT_KEYS:
        if k in rec and rec.get(k) is not None:
            return _amount_value(rec.get(k))
    return 0.0  # missing amount -> sensible default of 0


def _parse_date(v):
    """Return 'YYYY-MM-DD' (UTC) from an epoch or ISO-ish timestamp, else None."""
    if v is None:
        return None
    # numeric epoch (seconds / millis / micros)
    if isinstance(v, (int, float)) and not isinstance(v, bool):
        return _epoch_to_date(float(v))
    if isinstance(v, str):
        s = v.strip()
        if not s:
            return None
        # pure-numeric string -> epoch
        num = s[1:] if s.startswith("-") else s
        if num.isdigit():
            try:
                return _epoch_to_date(float(s))
            except (ValueError, OverflowError, OSError):
                return None
        # ISO-8601 style
        iso = s.replace("Z", "+00:00")
        try:
            dt = datetime.fromisoformat(iso)
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=timezone.utc)
            return dt.astimezone(timezone.utc).date().isoformat()
        except ValueError:
            # last resort: leading YYYY-MM-DD token
            head = s[:10]
            try:
                datetime.strptime(head, "%Y-%m-%d")
                return head
            except ValueError:
                return None
    return None


def _epoch_to_date(x):
    # heuristics: >1e14 micros, >1e11 millis, else seconds
    if abs(x) > 1e14:
        x = x / 1_000_000.0
    elif abs(x) > 1e11:
        x = x / 1_000.0
    try:
        return datetime.fromtimestamp(x, tz=timezone.utc).date().isoformat()
    except (ValueError, OverflowError, OSError):
        return None


def _extract_date(rec):
    for k in DATE_KEYS:
        if k in rec and rec.get(k) is not None:
            d = _parse_date(rec.get(k))
            if d is not None:
                return d
    return None


_PARSED_SCHEMA = StructType([
    StructField("event_date", StringType(), True),
    StructField("revenue", DoubleType(), False),
])


def parse_line(line):
    """(event_date_str, revenue) for one NDJSON line. Never raises."""
    if line is None:
        return (None, 0.0)
    s = line.strip()
    if not s:
        return (None, 0.0)
    try:
        rec = json.loads(s)
    except (ValueError, TypeError):
        return (None, 0.0)
    if not isinstance(rec, dict):
        return (None, 0.0)
    return (_extract_date(rec), _extract_amount(rec))


# --------------------------------------------------------------------------- #
# Pipeline
# --------------------------------------------------------------------------- #
def build_gold(spark, input_path):
    raw = spark.read.text(input_path)

    parse_udf = F.udf(parse_line, _PARSED_SCHEMA)

    parsed = (
        raw
        .withColumn("p", parse_udf(F.col("value")))
        .select(
            F.col("p.event_date").alias("event_date_str"),
            F.col("p.revenue").alias("revenue"),
        )
    )

    # gold grain is a UTC calendar day; records without a usable date cannot be
    # placed on the daily calendar, so they are excluded from the daily table.
    gold = (
        parsed
        .where(F.col("event_date_str").isNotNull())
        .groupBy(F.to_date(F.col("event_date_str")).alias("event_date"))
        .agg(F.sum(F.coalesce(F.col("revenue"), F.lit(0.0))).alias("revenue"))
        .select(
            F.col("event_date").cast("date").alias("event_date"),
            F.col("revenue").cast("double").alias("revenue"),
        )
        .orderBy("event_date")
    )
    return gold


def main():
    input_path = os.environ.get("AGENT_INPUT_PATH", DEFAULT_INPUT)
    out_path = os.environ.get("AGENT_OUTPUT_PATH")
    out_table = os.environ.get("AGENT_OUTPUT_TABLE")

    spark = (
        SparkSession.builder
        .appName("p11_schema_evolution")
        .getOrCreate()
    )
    spark.sparkContext.setLogLevel("WARN")

    try:
        gold = build_gold(spark, input_path)
        gold.createOrReplaceTempView("gold_daily")

        if out_path:
            gold.write.mode("overwrite").parquet(out_path)
        elif out_table:
            gold.write.mode("overwrite").saveAsTable(out_table)
