def _to_utc_date(v):
    """Normalize a timestamp/date value to a UTC calendar-day string 'YYYY-MM-DD'."""
    if v is None:
        return None
    # Numeric epoch (seconds or millis)
    if isinstance(v, (int, float)) and not isinstance(v, bool):
        x = float(v)
        # Heuristic: treat very large values as milliseconds
        if x > 1e12:
            x = x / 1000.0
        try:
            return datetime.fromtimestamp(x, tz=timezone.utc).strftime("%Y-%m-%d")
        except Exception:
            return None
    if isinstance(v, str):
        s = v.strip()
        if not s:
            return None
        # Pure date already
        if len(s) >= 10 and s[4] == "-" and s[7] == "-":
            # Could be date or full ISO timestamp; parse robustly to UTC.
            try:
                iso = s.replace("Z", "+00:00")
                dt = datetime.fromisoformat(iso)
                if dt.tzinfo is None:
                    dt = dt.replace(tzinfo=timezone.utc)
                else:
                    dt = dt.astimezone(timezone.utc)
                return dt.strftime("%Y-%m-%d")
            except Exception:
                return s[:10]
        # Numeric string epoch
        try:
            x = float(s)
            if x > 1e12:
                x = x / 1000.0
            return datetime.fromtimestamp(x, tz=timezone.utc).strftime("%Y-%m-%d")
        except Exception:
            return None
    return None


def _num(v):
    if v is None or isinstance(v, bool):
        return None
    if isinstance(v, (int, float)):
        return float(v)
    if isinstance(v, str):
        try:
            return float(v.strip())
