    if isinstance(item, dict):
        # direct amount field
        for k in LINE_ITEM_AMOUNT_KEYS:
            if k in item:
                n = _num(item[k])
                if n is not None:
                    # if there's an explicit qty and this key looks like unit price, multiply
                    if k in ("price", "value"):
                        for qk in QTY_KEYS:
                            if qk in item:
                                q = _num(item[qk])
