def _coerce_number(x):
    if x is None:
        return None
    if isinstance(x, bool):
        return None
    if isinstance(x, (int, float)):
        return float(x)
    if isinstance(x, str):
        try:
            return float(x.strip())
        except Exception:
            return None
    return None


def _line_item_amount(it):
    """Extract a monetary value from a single line-item element."""
    n = _coerce_number(it)
    if n is not None:
        return n
    if isinstance(it, dict):
        # direct monetary fields
        for k in ("amount", "total", "line_total", "subtotal", "value"):
            if k in it:
                v = _coerce_number(it[k])
                if v is not None:
                    return v
        # price * qty
        price = None
        for k in ("price", "unit_price", "unitPrice", "cost"):
            if k in it:
                price = _coerce_number(it[k])
                if price is not None:
                    break
        if price is not None:
            qty = None
            for k in ("qty", "quantity", "count", "units"):
                if k in it:
                    qty = _coerce_number(it[k])
                    if qty is not None:
                        break
            if qty is None:
                qty = 1.0
            return price * qty
    return 0.0


def parse_revenue(raw):
    """Return the revenue for a raw JSON line, tolerant to shape changes."""
    if raw is None:
        return 0.0
    try:
        rec = json.loads(raw)
    except Exception:
