    if not isinstance(rec, dict):
        return 0.0

    for k in _AMOUNT_KEYS:
        if k in rec and rec[k] is not None:
            v = rec[k]
            # newer shape: list of line items
            if isinstance(v, list):
                total = 0.0
                for it in v:
                    total += _line_item_amount(it)
                return float(total)
            # older shape: single number (or numeric string)
            n = _coerce_number(v)
            if n is not None:
                return float(n)
    # missing amount -> sensible default
    return 0.0


def _epoch_to_utc_date(num):
    # heuristics for seconds / millis / micros
    try:
        n = float(num)
    except Exception:
        return None
    # millis
    if n > 1e14:      # micros
        n = n / 1_000_000.0
    elif n > 1e11:    # millis
        n = n / 1000.0
    try:
        dt = datetime.fromtimestamp(n, tz=timezone.utc)
        return dt.strftime("%Y-%m-%d")
    except Exception:
        return None


def _string_to_utc_date(s):
    s = s.strip()
    if not s:
        return None
    # pure numeric string -> epoch
    try:
        return _epoch_to_utc_date(float(s))
    except Exception:
        pass
    txt = s.replace("Z", "+00:00")
    # try full ISO
    for candidate in (txt, txt.replace(" ", "T")):
        try:
            dt = datetime.fromisoformat(candidate)
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=timezone.utc)
            else:
                dt = dt.astimezone(timezone.utc)
            return dt.strftime("%Y-%m-%d")
        except Exception:
            continue
    # fall back to leading YYYY-MM-DD
    if len(s) >= 10 and s[4] == "-" and s[7] == "-":
        head = s[:10]
        try:
            datetime.strptime(head, "%Y-%m-%d")
            return head
        except Exception:
            return None
    return None


def parse_event_date(raw):
    """Return UTC calendar day 'YYYY-MM-DD' for a raw JSON line."""
    if raw is None:
        return None
    try:
        rec = json.loads(raw)
    except Exception:
        return None
    if not isinstance(rec, dict):
        return None
    for k in _DATE_KEYS:
        if k in rec and rec[k] is not None:
            v = rec[k]
            if isinstance(v, (int, float)) and not isinstance(v, bool):
                d = _epoch_to_utc_date(v)
                if d:
                    return d
            elif isinstance(v, str):
                d = _string_to_utc_date(v)
                if d:
                    return d
    return None


def build_gold(spark, input_path):
    raw_df = spark.read.text(input_path).withColumnRenamed("value", "raw")

    rev_udf = F.udf(parse_revenue, DoubleType())
    date_udf = F.udf(parse_event_date, StringType())

