AMOUNT_KEYS = ['amount', 'revenue', 'total', 'value', 'amount_usd', 'grand_total']
LINE_ITEM_KEYS = ['line_items', 'items', 'lines', 'order_items']
ITEM_VALUE_KEYS = ['amount', 'line_total', 'subtotal', 'total', 'value', 'price', 'unit_price']
QTY_KEYS = ['qty', 'quantity', 'count', 'units', 'num']


def _num(v):
    if v is None or isinstance(v, bool):
