            return None
    return None


def _to_date(v):
    """Parse a value into a UTC calendar day (datetime.date) or None."""
    if v is None or isinstance(v, bool):
        return None
    # numeric epoch (seconds or millis)
    if isinstance(v, (int, float)):
        ts = float(v)
        if ts > 1e11:  # looks like milliseconds
            ts = ts / 1000.0
        try:
            return dt.datetime.fromtimestamp(ts, tz=timezone.utc).date()
        except Exception:
            return None
    if isinstance(v, str):
        s = v.strip()
        if s == '':
            return None
        # numeric string epoch
        try:
            n = float(s)
            ts = n / 1000.0 if n > 1e11 else n
            return dt.datetime.fromtimestamp(ts, tz=timezone.utc).date()
        except Exception:
            pass
        # ISO-8601 (handle trailing Z)
        s2 = s.replace('Z', '+00:00')
        try:
            d = dt.datetime.fromisoformat(s2)
            if d.tzinfo is None:
                d = d.replace(tzinfo=timezone.utc)
            return d.astimezone(timezone.utc).date()
        except Exception:
            pass
        # plain date formats
        for fmt in ('%Y-%m-%d', '%Y/%m/%d', '%m/%d/%Y', '%Y%m%d'):
            try:
                return dt.datetime.strptime(s[:10] if fmt != '%Y%m%d' else s[:8], fmt).date()
            except Exception:
                continue
    return None


def _item_value(item):
    """Revenue contribution of one line item (number or dict)."""
    if item is None:
        return 0.0
    n = _num(item)
    if n is not None:
        return n
    if isinstance(item, dict):
        qty = None
        for k in QTY_KEYS:
            if k in item:
                q = _num(item[k])
                if q is not None:
                    qty = q
                    break
        for k in ITEM_VALUE_KEYS:
            if k in item and item[k] is not None:
                val = _num(item[k])
                if val is not None:
                    # unit price * quantity when we have a per-unit price
                    if k in ('price', 'unit_price') and qty is not None:
                        return val * qty
                    return val
        # fallback: sum any numeric leaf values
        tot, found = 0.0, False
        for vv in item.values():
            nn = _num(vv)
            if nn is not None:
                tot += nn
                found = True
        return tot if found else 0.0
    return 0.0


def _amount(rec):
    """Compute revenue tolerating scalar amount or list-of-line-items."""
    for k in AMOUNT_KEYS:
        if k in rec and rec[k] is not None:
            v = rec[k]
            if isinstance(v, list):
                return sum(_item_value(it) for it in v)
            n = _num(v)
            if n is not None:
                return n
            if isinstance(v, dict):
                return _item_value(v)
    for k in LINE_ITEM_KEYS:
        if k in rec and isinstance(rec[k], list):
            return sum(_item_value(it) for it in rec[k])
    # missing amount -> sensible default
    return 0.0


def parse_line(line):
