def _to_float(x):
    """Coerce anything vaguely numeric to float; else 0.0."""
    if x is None:
        return 0.0
    if isinstance(x, bool):
        return 0.0
    if isinstance(x, (int, float)):
        return float(x)
    if isinstance(x, str):
        try:
            return float(x.strip())
        except Exception:
            return 0.0
    return 0.0


def parse_amount(a):
    """Revenue for a single order.

    Handles the OLD shape (single number) and the NEW shape
    (list of line items, each a number or a dict with amount/price*qty/value).
    """
    if a is None:
        return 0.0
    if isinstance(a, bool):
        return 0.0
    if isinstance(a, (int, float)):
        return float(a)
    if isinstance(a, str):
        return _to_float(a)
    if isinstance(a, list):
        total = 0.0
        for it in a:
            if isinstance(it, (int, float)) and not isinstance(it, bool):
                total += float(it)
            elif isinstance(it, str):
                total += _to_float(it)
            elif isinstance(it, dict):
                if "amount" in it and it["amount"] is not None:
                    total += parse_amount(it["amount"])
                elif "price" in it:
                    price = _to_float(it.get("price"))
                    qty = it.get("quantity", it.get("qty", 1))
                    q = _to_float(qty)
                    if q == 0.0:
                        q = 1.0
                    total += price * q
                elif "value" in it and it["value"] is not None:
                    total += parse_amount(it["value"])
                elif "total" in it and it["total"] is not None:
                    total += parse_amount(it["total"])
        return total
