    return None


def to_utc_date(v):
    """Return an ISO 'YYYY-MM-DD' UTC calendar day, or None."""
    if v is None:
        return None
    # numeric epoch (seconds or millis)
    if isinstance(v, (int, float)) and not isinstance(v, bool):
        val = float(v)
        if val > 1e11:      # milliseconds
            val = val / 1000.0
        try:
            return datetime.fromtimestamp(val, tz=timezone.utc).date().isoformat()
        except Exception:
            return None
    if isinstance(v, str):
        s = v.strip()
        if not s:
            return None
        # numeric-looking string epoch
        try:
            fv = float(s)
            if fv > 1e8:  # looks like an epoch, not a small number
                if fv > 1e11:
                    fv = fv / 1000.0
                return datetime.fromtimestamp(fv, tz=timezone.utc).date().isoformat()
        except Exception:
            pass
        # ISO-8601
        try:
            s2 = s.replace("Z", "+00:00")
            dt = datetime.fromisoformat(s2)
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=timezone.utc)
            return dt.astimezone(timezone.utc).date().isoformat()
        except Exception:
            pass
        # bare date prefix
        try:
            return datetime.strptime(s[:10], "%Y-%m-%d").date().isoformat()
        except Exception:
            return None
    return None


def parse_line(line):
