LINE_AMOUNT_KEYS = ["amount", "price", "unit_price", "value", "total", "cost"]
QTY_KEYS = ["qty", "quantity", "count", "units"]


def _num(x):
    """Coerce a value to float, tolerantly. Returns None on failure."""
    if x is None:
        return None
    if isinstance(x, bool):
        return None
    if isinstance(x, (int, float)):
        return float(x)
