def _line_item_value(item):
    """Revenue contribution of a single line item (scalar or dict)."""
    v = _num(item)
    if v is not None:
        return v
    if isinstance(item, dict):
        price = None
        for k in LINE_AMOUNT_KEYS:
            if k in item:
                price = _num(item[k])
                if price is not None:
                    break
        if price is None:
            return 0.0
        qty = None
        for k in QTY_KEYS:
            if k in item:
                qty = _num(item[k])
                if qty is not None:
                    break
        if qty is None:
            qty = 1.0
        return price * qty
    return 0.0


def _compute_amount(amt):
    """Handle scalar amount OR a list of line items. Missing -> 0.0 default."""
    if amt is None:
