def _to_utc_date(ts):
    """Parse a timestamp (epoch or ISO string) into a UTC 'YYYY-MM-DD' string."""
    if ts is None:
        return None
    # numeric epoch (seconds / millis / micros)
    n = None
    if isinstance(ts, (int, float)) and not isinstance(ts, bool):
        n = float(ts)
    elif isinstance(ts, str):
        s = ts.strip()
        if s == "":
            return None
        # pure numeric string -> epoch
        try:
            n = float(s)
        except ValueError:
            n = None
        if n is None:
            # ISO-ish string
            iso = s.replace("Z", "+00:00")
            for fmt in (None,):
                try:
                    dt = datetime.fromisoformat(iso)
                    if dt.tzinfo is None:
                        dt = dt.replace(tzinfo=timezone.utc)
                    return dt.astimezone(timezone.utc).strftime("%Y-%m-%d")
                except ValueError:
                    pass
            # fall back to leading date token 'YYYY-MM-DD...'
            token = s.split("T")[0].split(" ")[0]
            try:
                dt = datetime.strptime(token, "%Y-%m-%d")
                return dt.strftime("%Y-%m-%d")
            except ValueError:
                return None
    if n is not None:
        # normalize epoch magnitude to seconds
        if n > 1e17:      # nanoseconds
            n = n / 1e9
        elif n > 1e14:    # microseconds
            n = n / 1e6
        elif n > 1e11:    # milliseconds
            n = n / 1e3
        try:
            dt = datetime.fromtimestamp(n, tz=timezone.utc)
            return dt.strftime("%Y-%m-%d")
        except (OverflowError, OSError, ValueError):
            return None
    return None


