        except Exception:
            return None
    if isinstance(v, str):
        s = v.strip()
        if not s:
            return None
        # numeric-looking epoch string
        try:
            x = float(s)
            if x > 1e12:
                x /= 1000.0
            return datetime.fromtimestamp(x, tz=timezone.utc).strftime("%Y-%m-%d")
        except Exception:
            pass
        # ISO-8601 timestamp
        try:
            s2 = s.replace("Z", "+00:00")
            dt = datetime.fromisoformat(s2)
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=timezone.utc)
            return dt.astimezone(timezone.utc).strftime("%Y-%m-%d")
        except Exception:
            pass
        # plain date prefix YYYY-MM-DD
        if len(s) >= 10:
            return s[:10]
    return None


