    except Exception:
        cols = []
    lower = {c.lower(): c for c in cols}
    picked = {}
    for role, cands in _CAND.items():
        for c in cands:
            if c.lower() in lower:
                picked[role] = lower[c.lower()]
                break
    return picked

_COL = _detect()

def _c(role):
    return F.col(_COL[role])

