                 .when(op_norm.isin("delete", "d", "remove", "removed", "del", "3"), F.lit("removed"))
                 .when(op_norm.isin("update", "u", "change", "changed", "modify", "upsert", "2"), F.lit("changed"))
                 .otherwise(F.lit("changed")))

    if "ts" in _COL:
        tsp = F.coalesce(
            F.to_timestamp(_c("ts").cast("string")),
            F.timestamp_seconds(_c("ts").cast("long")),
