from pyspark.sql import SparkSession, functions as F

DATA = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_payments_seed5772.ndjson"

# ---- lazy schema detection (only reference columns that truly exist) --------
_META = None


def _meta():
    global _META
    if _META is None:
        try:
            cols = SparkSession.active().read.json(DATA).columns
        except Exception:
            cols = []
        low = {c.lower(): c for c in cols}

        def pick(*cands):
            for c in cands:
                if c.lower() in low:
                    return low[c.lower()]
            return None

        _META = {
            "cols": cols,
            "type": pick("type", "event_type", "record_type", "kind",
                         "source", "feed", "stream", "channel"),
            "ts": pick("event_ts", "event_time", "timestamp", "ts",
                       "created_at", "occurred_at", "time", "datetime"),
            "date": pick("settlement_date", "value_date", "as_of_date",
                         "rate_date", "business_date", "date", "day"),
            "ccy": pick("currency", "ccy", "currency_code", "curr", "iso_currency"),
            "amt": pick("amount", "native_amount", "amount_native", "value",
                        "settled_amount", "amount_local", "local_amount"),
            "rate": pick("fx_rate", "usd_rate", "rate_to_usd", "exchange_rate",
                         "rate", "fx"),
            "usd": pick("usd_amount", "amount_usd", "settled_usd", "usd_value",
                        "usd", "usd_settled"),
        }
    return _META


def _date_col(m, prefer_date=True):
    order = []
    if prefer_date and m["date"]:
        order.append(m["date"])
    if m["ts"]:
        order.append(m["ts"])
    if not prefer_date and m["date"]:
        order.append(m["date"])
    if not order:
        return F.lit(None).cast("date")
    parts = [F.to_date(F.substring(F.col(c).cast("string"), 1, 10)) for c in order]
    return F.coalesce(*parts)


def _ord_col(m):
    parts = []
    if m["ts"]:
        parts.append(F.col(m["ts"]).cast("string"))
    if m["date"]:
        parts.append(F.col(m["date"]).cast("string"))
    parts.append(F.lit(""))
    return F.coalesce(*parts)


def _type_has(m, *kw):
    if not m["type"]:
        return None
    tl = F.lower(F.col(m["type"]).cast("string"))
    cond = F.lit(False)
    for k in kw:
        cond = cond | tl.contains(k)
    return cond


def _is_rate(m):
    th = _type_has(m, "rate", "fx")
    if th is not None:
        return th
    return F.col(m["rate"]).isNotNull() if m["rate"] else F.lit(False)


def _is_ext(m):
    th = _type_has(m, "ext", "bank", "external", "recon", "statement")
    if th is not None:
        return th
    return F.col(m["usd"]).isNotNull() if m["usd"] else F.lit(False)


def _is_pay(m):
    rate = _type_has(m, "rate", "fx")
    ext = _type_has(m, "ext", "bank", "external", "recon", "statement")
    if rate is not None and ext is not None:
        return ~(rate | ext)
    cond = F.col(m["amt"]).isNotNull() if m["amt"] else F.lit(True)
    if m["rate"]:
        cond = cond & F.col(m["rate"]).isNull()
    if m["usd"]:
        cond = cond & F.col(m["usd"]).isNull()
    return cond


def _ccy(m):
    return F.col(m["ccy"]).cast("string") if m["ccy"] else F.lit(None).cast("string")


# ---- pipeline datasets ------------------------------------------------------
@dp.materialized_view(name="payments_raw")
def payments_raw():
    return SparkSession.active().read.json(DATA)


@dp.materialized_view(name="payments_native")
def payments_native():
    m = _meta()
    df = SparkSession.active().read.table("spark_catalog.default.payments_raw")
    amt = F.col(m["amt"]).cast("double") if m["amt"] else F.lit(0.0)
    norm = df.where(_is_pay(m)).select(
        _date_col(m, True).alias("settlement_date"),
        _ccy(m).alias("currency"),
        amt.alias("native_amount"),
    )
    return (norm.where(F.col("settlement_date").isNotNull())
                .groupBy("settlement_date", "currency")
                .agg(F.round(F.sum("native_amount"), 2).alias("native_amount")))


@dp.materialized_view(name="fx_rates_daily")
def fx_rates_daily():
    m = _meta()
    df = SparkSession.active().read.table("spark_catalog.default.payments_raw")
    rate = F.col(m["rate"]).cast("double") if m["rate"] else F.lit(None).cast("double")
    norm = df.where(_is_rate(m)).select(
        _date_col(m, True).alias("settlement_date"),
        _ccy(m).alias("currency"),
        rate.alias("rate"),
        _ord_col(m).alias("ord"),
    )
    # deterministic: rate effective that day = rate at latest ordering key
    return (norm.where(F.col("settlement_date").isNotNull())
                .groupBy("settlement_date", "currency")
                .agg(F.max_by(F.col("rate"), F.col("ord")).alias("rate")))


@dp.materialized_view(name="external_settlements")
def external_settlements():
    m = _meta()
    df = SparkSession.active().read.table("spark_catalog.default.payments_raw")
    usd = F.col(m["usd"]).cast("double") if m["usd"] else F.lit(None).cast("double")
    norm = df.where(_is_ext(m)).select(
        _date_col(m, True).alias("settlement_date"),
        _ccy(m).alias("currency"),
        usd.alias("external_usd"),
    )
    return (norm.where(F.col("settlement_date").isNotNull())
                .groupBy("settlement_date", "currency")
                .agg(F.round(F.sum("external_usd"), 2).alias("external_usd")))


@dp.materialized_view(name="settlement_by_currency")
def settlement_by_currency():
    spark = SparkSession.active()
    pay = spark.read.table("spark_catalog.default.payments_native")
    rates = spark.read.table("spark_catalog.default.fx_rates_daily")
    j = pay.join(rates, ["settlement_date", "currency"], "left")
    # USD converts 1:1 if no explicit rate row is present
    eff_rate = F.coalesce(
        F.col("rate"),
        F.when(F.upper(F.col("currency")) == F.lit("USD"), F.lit(1.0)),
    )
    return j.select(
        "settlement_date",
        "currency",
        F.col("native_amount"),
        eff_rate.alias("rate"),
        F.round(F.col("native_amount") * eff_rate, 2).alias("usd_amount"),
    )


@dp.materialized_view(name="settlement_daily")
def settlement_daily():
    byc = SparkSession.active().read.table(
        "spark_catalog.default.settlement_by_currency")
    return (byc.groupBy("settlement_date")
               .agg(F.round(F.sum("usd_amount"), 2).alias("usd_total")))


@dp.materialized_view(name="settlement_reconciliation")
def settlement_reconciliation():
    spark = SparkSession.active()
    byc = spark.read.table("spark_catalog.default.settlement_by_currency") \
        .select("settlement_date", "currency", "usd_amount")
    ext = spark.read.table("spark_catalog.default.external_settlements")
    j = byc.join(ext, ["settlement_date", "currency"], "full_outer")
    internal = F.coalesce(F.col("usd_amount"), F.lit(0.0))
    external = F.coalesce(F.col("external_usd"), F.lit(0.0))
    diff = F.round(internal - external, 2)
    return j.select(
        "settlement_date",
        "currency",
        F.round(internal, 2).alias("internal_usd"),
        F.round(external, 2).alias("external_usd"),
        diff.alias("diff"),
        (F.abs(diff) < F.lit(0.01)).alias("matched"),
        F.col("usd_amount").isNull().alias("missing_internal"),
        F.col("external_usd").isNull().alias("missing_external"),
    )

