# Columns that plausibly encode "recency"/version so we can pick the true latest row.
_TIME_CANDIDATES = [
    "ts", "event_ts", "event_time", "eventtime", "updated_at", "update_ts",
    "timestamp", "seq", "sequence", "version", "ingest_ts", "ingested_at",
    "_ingested_at", "emitted_at", "batch_ts", "load_ts", "offset", "revision",
