from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F, Window
from pyspark.sql.types import StructType, StructField, StringType, DoubleType

PAY_PATH = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_payments_seed42.ndjson"
FX_PATH  = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_fx_rates_cdc_seed42.ndjson"

# Candidate key names (explicit schema => any listed key resolves; absent -> null)
PAY_ID   = ["payment_id", "id", "txn_id", "transaction_id", "event_id"]
PAY_CCY  = ["currency", "ccy", "currency_code", "curr"]
PAY_AMT  = ["amount", "value", "amt", "foreign_amount", "payment_amount", "original_amount"]
PAY_TS   = ["event_time", "occurred_at", "ts", "timestamp", "event_ts", "created_at",
            "payment_time", "time", "event_timestamp", "payment_ts"]

FX_CCY   = ["currency", "ccy", "currency_code", "curr"]
FX_RATE  = ["rate", "fx_rate", "usd_rate", "rate_to_usd", "rate_usd", "price",
            "exchange_rate", "conversion_rate"]
FX_TS    = ["rate_ts", "event_time", "ts", "timestamp", "effective_time", "updated_at",
            "as_of", "valid_from", "time", "created_at", "effective_ts",
            "event_timestamp", "rate_time"]
FX_OP    = ["op", "operation", "_op", "cdc_op", "change_type", "_change_type"]


def _schema(str_cols, dbl_cols):
    seen, fields = set(), []
    for c in str_cols:
        if c not in seen:
            seen.add(c); fields.append(StructField(c, StringType(), True))
    for c in dbl_cols:
        if c not in seen:
            seen.add(c); fields.append(StructField(c, DoubleType(), True))
    return StructType(fields)


PAY_SCHEMA = _schema(PAY_ID + PAY_CCY + PAY_TS, PAY_AMT)
FX_SCHEMA  = _schema(FX_CCY + FX_TS + FX_OP, FX_RATE)


def _coal(cols):
    return F.coalesce(*[F.col(c) for c in cols])


@dp.materialized_view(name="payments_clean")
def payments_clean():
    df = SparkSession.active().read.schema(PAY_SCHEMA).json(PAY_PATH)
    return (
        df.select(
            _coal(PAY_ID).alias("pay_id"),
            _coal(PAY_CCY).alias("ccy"),
            _coal(PAY_AMT).cast("double").alias("amt"),
            _coal(PAY_TS).alias("pts_str"),
        )
        .withColumn("pts", F.col("pts_str").cast("timestamp"))
        .withColumn("settlement_date", F.to_date(F.substring("pts_str", 1, 10), "yyyy-MM-dd"))
        .select("pay_id", "ccy", "amt", "pts", "settlement_date")
    )


@dp.materialized_view(name="fx_clean")
def fx_clean():
    df = SparkSession.active().read.schema(FX_SCHEMA).json(FX_PATH)
    out = (
        df.select(
            _coal(FX_CCY).alias("fx_ccy"),
            _coal(FX_RATE).cast("double").alias("rate"),
            _coal(FX_TS).alias("rts_str"),
            _coal(FX_OP).alias("op"),
        )
        .withColumn("rts", F.col("rts_str").cast("timestamp"))
    )
    # Drop tombstone/delete CDC events; keep inserts/updates and untyped rows
    return out.where(
        F.col("op").isNull() | (~F.lower(F.col("op")).isin("delete", "d", "del"))
    ).select("fx_ccy", "rate", "rts")


@dp.materialized_view(name="payments_usd")
def payments_usd():
    spark = SparkSession.active()
    p = spark.read.table("payments_clean")
    r = spark.read.table("fx_clean")

    # As-of join: only rates in effect at or before the payment moment.
    joined = p.join(
        r,
        (p["ccy"] == r["fx_ccy"]) & (r["rts"] <= p["pts"]),
        "left",
    )

    w = Window.partitionBy("pay_id").orderBy(F.col("rts").desc_nulls_last())
    latest = joined.withColumn("rn", F.row_number().over(w)).where(F.col("rn") == 1)

    rate_final = F.when(F.col("ccy") == F.lit("USD"), F.lit(1.0)).otherwise(F.col("rate"))

    return latest.select(
        "pay_id",
        "ccy",
        "amt",
        "pts",
        "settlement_date",
        rate_final.alias("applied_rate"),
        F.col("rts").alias("rate_applied_ts"),  # audit: as-applied rate timestamp
        (F.col("amt") * rate_final).alias("usd_amount"),
    )


@dp.materialized_view(name="usd_daily")
def usd_daily():
    pu = SparkSession.active().read.table("payments_usd")
    return (
        pu.groupBy("settlement_date")
        .agg(F.sum("usd_amount").alias("usd_total"))
        .select("settlement_date", "usd_total")
    )

