        F.col("currency"),
        F.col("pay_ts"),
        F.col("settlement_date"),
        F.col("b.rate").alias("fx_rate"),
        F.col("b.rate_ts").alias("rate_ts"),  # as-applied rate timestamp (audit)
        (F.col("fx_amount") * F.col("b.rate")).alias("usd_amount"),
