# ---- pure-Python schema sniff at import time (NOT inside a query fn) ----
def _sample(uri, n=800):
    path = uri.replace("file://", "")
    agg = {}
    try:
        with open(path) as f:
            for i, line in enumerate(f):
                if i >= n:
                    break
                line = line.strip()
                if not line:
                    continue
                try:
                    obj = json.loads(line)
                except Exception:
                    continue
                if isinstance(obj, dict):
                    for k, v in obj.items():
                        if k not in agg and v is not None:
                            agg[k] = v
    except Exception:
        pass
    return agg


def _pick(sample, cands, exclude=()):
    cols = list(sample.keys())
    low = {c.lower(): c for c in cols}
    ex = {e.lower() for e in exclude}
    for cand in cands:
        c = low.get(cand.lower())
        if c and c.lower() not in ex:
            return c
    for cand in cands:
        for c in cols:
            if cand.lower() in c.lower() and c.lower() not in ex:
                return c
    return None


PAY = _sample(PAY_URI)
FX = _sample(FX_URI)

PID = _pick(PAY, ["payment_id", "id", "txn_id", "transaction_id", "payment"])
PAMT = _pick(PAY, ["amount", "foreign_amount", "amount_foreign", "value", "fx_amount", "amt"])
PCUR = _pick(PAY, ["currency", "ccy", "currency_code", "curr"])
PTS = _pick(PAY, ["event_time", "event_timestamp", "payment_time", "occurred_at",
                  "paid_at", "created_at", "timestamp", "ts", "time"])

RCUR = _pick(FX, ["currency", "ccy", "currency_code", "curr"])
RRATE = _pick(FX, ["rate", "fx_rate", "usd_rate", "rate_to_usd", "exchange_rate", "price"])
RTS = _pick(FX, ["rate_time", "rate_timestamp", "effective_time", "effective_at",
                 "valid_from", "as_of", "updated_at", "timestamp", "ts", "time"])
ROP = _pick(FX, ["op", "operation", "cdc_op", "change_type", "_op"])


def _ts_expr(colname, sample):
    """Return a timestamp column expression robust to string ISO or epoch."""
    v = sample.get(colname)
    if isinstance(v, bool):
        v = None
    if isinstance(v, (int, float)):
        if float(v) > 1e12:          # epoch millis
            return (F.col(colname).cast("double") / 1000.0).cast("timestamp")
        return F.col(colname).cast("double").cast("timestamp")  # epoch seconds
    return F.to_timestamp(F.col(colname))  # ISO-8601 string


@dp.materialized_view(name="payments_enriched")
def payments_enriched():
    spark = SparkSession.active()

    p = spark.read.json(PAY_URI).select(
        F.col(PID).cast("string").alias("payment_id"),
        F.col(PAMT).cast("double").alias("foreign_amount"),
        F.upper(F.trim(F.col(PCUR).cast("string"))).alias("currency"),
        _ts_expr(PTS, PAY).alias("pay_ts"),
    )

    r = spark.read.json(FX_URI)
    if ROP is not None:
        r = r.where(
            ~F.lower(F.trim(F.col(ROP).cast("string"))).isin("delete", "d", "remove")
        )
    r = r.select(
        F.upper(F.trim(F.col(RCUR).cast("string"))).alias("currency"),
        F.col(RRATE).cast("double").alias("rate"),
        _ts_expr(RTS, FX).alias("rate_ts"),
    ).where(F.col("rate").isNotNull() & F.col("rate_ts").isNotNull())

    # As-of join: for each payment, the rate whose rate_ts is the greatest
    # value that is still <= pay_ts (never a rate stamped after the payment).
    qual = (
        p.join(r, on="currency", how="inner")
        .where(F.col("rate_ts") <= F.col("pay_ts"))
    )
    w = Window.partitionBy("payment_id").orderBy(
        F.col("rate_ts").desc(), F.col("rate").desc()
    )
    asof = (
        qual.withColumn("rn", F.row_number().over(w))
        .where(F.col("rn") == 1)
        .select(
            "payment_id",
            F.col("rate").alias("applied_rate"),
            F.col("rate_ts").alias("rate_ts"),
        )
    )

    # Left join back so no foreign payment is lost even if no prior rate exists.
    enriched = (
        p.join(asof, on="payment_id", how="left")
        .withColumn("usd_amount", F.col("foreign_amount") * F.col("applied_rate"))
        .withColumn("settlement_date", F.to_date(F.col("pay_ts")))
    )
    return enriched.select(
        "payment_id",
        "currency",
        "foreign_amount",
        "pay_ts",
        "applied_rate",
        "rate_ts",          # as-applied rate timestamp carried through for audit
        "usd_amount",
        "settlement_date",
    )


@dp.materialized_view(name="usd_daily")
def usd_daily():
    src = SparkSession.active().read.table("payments_enriched")
    return (
        src.groupBy(F.col("settlement_date").alias("settlement_date"))
        .agg(F.sum("usd_amount").cast("double").alias("usd_total"))
        .select("settlement_date", "usd_total")
    )

