                             "as_of", "asof", "valid_from", "updated_at",
                             "event_time", "timestamp", "ts", "time"], "ts")


def _ts(schema, name):
    dt = schema.get(name, "string").lower()
    c = F.col(name)
    if "timestamp" in dt:
        return c
    if "string" in dt:
        return F.to_timestamp(c)
    # numeric epoch: heuristically choose millis vs seconds
    cl = c.cast("long")
    return F.when(F.abs(cl) > F.lit(100000000000),
                  F.timestamp_millis(cl)).otherwise(F.timestamp_seconds(cl))


@dp.materialized_view(name="payments_enriched")
def payments_enriched():
    spark = SparkSession.getActiveSession()

    pay = spark.read.json(PAY_PATH).select(
