from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F, Window
import json

PAY_PATH = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_payments_seed14142.ndjson"
FX_PATH  = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_fx_rates_cdc_seed14142.ndjson"


def _spark():
    return SparkSession.active() or SparkSession.builder.getOrCreate()


# ---------- schema discovery (pure Python, no Spark job -> dry-run safe) ----------
def _read_records(path, n=500):
    local = path[len("file://"):] if path.startswith("file://") else path
    recs = []
    try:
        with open(local, "r") as fh:
            for line in fh:
                line = line.strip()
                if not line:
                    continue
                try:
                    recs.append(json.loads(line))
                except Exception:
                    pass
                if len(recs) >= n:
                    break
    except Exception:
        pass
    return recs


def _keys_and_samples(recs):
    keys, sample = [], {}
    for r in recs:
        if not isinstance(r, dict):
            continue
        for k, v in r.items():
            if k not in keys:
                keys.append(k)
            if k not in sample or (sample[k] is None and v is not None):
                sample[k] = v
    return keys, sample


def _tt(v):
    if isinstance(v, bool):
        return "string"
    if isinstance(v, (int, float)):
        a = abs(v)
        if a >= 1_000_000_000_000:
            return "timestamp_ms"
        if a >= 1_000_000_000:
            return "timestamp_s"
        return "numeric"
    return "string"


def _pick(names, exacts, contains, exclude):
    low = {n.lower(): n for n in names}
    for e in exacts:
        if e in low and low[e] not in exclude:
            return low[e]
    for n in names:
        if n in exclude:
            continue
        nl = n.lower()
        for kw in contains:
            if kw in nl:
                return n
    return None


def _detect():
    info = {"pay": {}, "fx": {}, "fx_flatten": None}

    pk, ps = _keys_and_samples(_read_records(PAY_PATH))
    pid = _pick(pk, ["payment_id", "id", "txn_id", "transaction_id", "payment_uuid", "uuid", "pmt_id"],
                ["payment_id", "txn", "uuid", "_id"], set())
    pamt = _pick(pk, ["amount", "value", "payment_amount", "amt", "local_amount", "amount_local", "original_amount"],
                 ["amount", "amt"], set())
    pcur = _pick(pk, ["currency", "ccy", "currency_code", "cur", "iso_currency", "local_currency"],
                 ["curr", "ccy"], {pamt})
    pts = _pick(pk, ["event_time", "payment_time", "occurred_at", "event_ts", "paid_at", "event_timestamp",
                     "created_at", "timestamp", "ts"], ["time", "_ts", "date"], {pid, pamt, pcur})
    info["pay"] = {"id": pid, "amount": pamt or "amount", "currency": pcur or "currency",
                   "ts": pts or "event_time", "ts_type": _tt(ps.get(pts))}

    frecs = _read_records(FX_PATH)
    fk, fs = _keys_and_samples(frecs)
    flat = None
    for k in fk:
        if isinstance(fs.get(k), dict) and k.lower() in ("after", "value", "data", "payload", "record", "fields"):
            flat = k
            break
    if flat:
        nrecs = [r[flat] for r in frecs if isinstance(r, dict) and isinstance(r.get(flat), dict)]
        fk, fs = _keys_and_samples(nrecs)
    info["fx_flatten"] = flat
    frate = _pick(fk, ["rate", "fx_rate", "exchange_rate", "usd_rate", "conversion_rate", "rate_usd", "price"],
                  ["rate"], set())
    fcur = _pick(fk, ["currency", "ccy", "currency_code", "cur", "iso_currency", "base_currency", "from_currency"],
                 ["curr", "ccy"], {frate})
    fts = _pick(fk, ["event_time", "rate_time", "effective_time", "effective_ts", "effective_at", "valid_from",
                     "rate_ts", "as_of", "asof", "updated_at", "timestamp", "ts"],
                ["time", "_ts", "date", "effective", "valid", "asof"], {frate, fcur})
    info["fx"] = {"rate": frate or "rate", "currency": fcur or "currency",
                  "ts": fts or "event_time", "ts_type": _tt(fs.get(fts))}
    return info


_INFO = _detect()


def _ts(name, typ):
    c = F.col(name)
    if typ == "timestamp_ms":
        return F.timestamp_millis(c.cast("long"))
    if typ == "timestamp_s":
        return F.timestamp_seconds(c.cast("long"))
    if typ and typ.startswith("timestamp"):
        return c
    return F.to_timestamp(c)


def _sdate(name, typ):
    if typ == "string":
        return F.to_date(F.substring(F.col(name), 1, 10))
    return F.to_date(_ts(name, typ))


def _utc():
    try:
        _spark().conf.set("spark.sql.session.timeZone", "UTC")
    except Exception:
        pass


# --------------------------------- pipeline ---------------------------------
@dp.materialized_view(name="payments_raw")
def payments_raw():
    return _spark().read.json(PAY_PATH)


@dp.materialized_view(name="fx_rates_norm")
def fx_rates_norm():
    _utc()
    fx = _INFO["fx"]
    df = _spark().read.json(FX_PATH)
    if _INFO["fx_flatten"]:
        df = df.select(F.col(_INFO["fx_flatten"] + ".*"))
    return df.select(
        F.upper(F.col(fx["currency"]).cast("string")).alias("fx_currency"),
        F.col(fx["rate"]).cast("double").alias("fx_rate"),
        _ts(fx["ts"], fx["ts_type"]).alias("rate_ts"),
    ).where(F.col("fx_rate").isNotNull() & F.col("rate_ts").isNotNull())


@dp.materialized_view(name="payments_enriched")
def payments_enriched():
    _utc()
    p = _INFO["pay"]
    pay = _spark().read.table("payments_raw")
    idcol = F.col(p["id"]) if p["id"] else F.monotonically_increasing_id()
    pay = pay.select(
        idcol.cast("string").alias("payment_id"),
        F.col(p["amount"]).cast("double").alias("amount"),
        F.upper(F.col(p["currency"]).cast("string")).alias("currency"),
        _ts(p["ts"], p["ts_type"]).alias("pay_ts"),
        _sdate(p["ts"], p["ts_type"]).alias("settlement_date"),
    )
    fx = _spark().read.table("fx_rates_norm")

    # point-in-time (as-of) join: only rates stamped at/before the payment moment
    cond = (pay["currency"] == fx["fx_currency"]) & (fx["rate_ts"] <= pay["pay_ts"])
    joined = pay.join(fx, cond, "left")

    w = Window.partitionBy("payment_id").orderBy(
        F.col("rate_ts").desc_nulls_last(), F.col("fx_rate").desc_nulls_last()
    )
    latest = joined.withColumn("_rn", F.row_number().over(w)).where(F.col("_rn") == 1)

    rate_used = F.coalesce(F.col("fx_rate"), F.when(F.col("currency") == "USD", F.lit(1.0)))
    return latest.select(
        "payment_id",
        "amount",
        "currency",
        "pay_ts",
        "settlement_date",
        F.col("fx_rate").alias("applied_rate"),
        F.col("rate_ts").alias("rate_ts"),          # as-applied rate timestamp (audit)
        (F.col("amount") * rate_used).alias("usd_amount"),
    )


@dp.materialized_view(name="usd_daily")
def usd_daily():
    _utc()
    e = _spark().read.table("payments_enriched")
    return e.groupBy(F.col("settlement_date").alias("settlement_date")) \
            .agg(F.sum("usd_amount").alias("usd_total"))

