def _peek_cols(uri, n=2000):
    path = uri[7:] if uri.startswith("file://") else uri
    cols = set()
    try:
        with open(path) as f:
            for i, line in enumerate(f):
                if i >= n:
                    break
                line = line.strip()
                if line:
                    try:
                        cols.update(json.loads(line).keys())
                    except Exception:
                        pass
    except Exception:
        pass
    return cols


def pick(cols, cands, exclude=None):
    low = {c.lower(): c for c in cols}
    ex = {e.lower() for e in (exclude or []) if e}
    for cand in cands:
        c = cand.lower()
        if c in low and c not in ex:
            return low[c]
    return None


PAY_COLS = _peek_cols(PAY)
FX_COLS = _peek_cols(FX)

