fx_rate = pick(FX_COLS, ["rate", "fx_rate", "usd_rate", "rate_to_usd", "conversion_rate",
                         "exchange_rate", "price", "usd_per_unit"])
fx_eff = pick(FX_COLS, ["effective_date", "eff_date", "rate_date", "as_of_date",
                        "valid_from", "valid_from_date", "business_date", "effective_from",
                        "start_date", "fx_date", "date"])
fx_rec = pick(FX_COLS, ["recorded_at", "recorded_ts", "change_ts", "change_time", "changed_at",
                        "updated_at", "update_ts", "ingested_at", "ingest_ts", "commit_ts",
                        "system_ts", "system_time", "as_of_ts", "cdc_ts", "cdc_timestamp",
                        "op_ts", "load_ts", "version_ts", "transaction_ts", "valid_from_ts",
                        "observed_at", "published_at", "created_at"], exclude=[fx_eff])
fx_ver = pick(FX_COLS, ["version", "rate_version", "seq", "seq_no", "revision",
                        "change_seq", "seq_num"])


def _d(colname):
    # UTC calendar day, tz-safe: take the leading YYYY-MM-DD
    return F.to_date(F.substring(F.col(colname).cast("string"), 1, 10))


@dp.materialized_view(name="payments_raw")
