@dp.materialized_view(name="usd_daily")
def usd_daily():
    spark = SparkSession.active()

    ccy_col = (F.col(pay_ccy).cast("string").alias("ccy")
               if pay_ccy else F.lit("USD").alias("ccy"))

    pay = spark.read.table("payments_raw").select(
        ccy_col,
        F.col(pay_amount).cast("double").alias("amount"),
        _d(pay_date).alias("pdate"),
    ).withColumn("_pid", F.monotonically_increasing_id())

    r_cols = [
        F.col(fx_ccy).cast("string").alias("rccy"),
        F.col(fx_rate).cast("double").alias("rate"),
        _d(fx_eff).alias("effdate"),
    ]
    if fx_rec:
        r_cols.append(F.col(fx_rec).cast("string").alias("recstr"))
        r_cols.append(_d(fx_rec).alias("recdate"))
    elif fx_ver:
        r_cols.append(F.col(fx_ver).cast("long").alias("ver"))

    fx = spark.read.table("fx_rates_raw").select(*r_cols)

    cond = (F.col("ccy") == F.col("rccy")) & (F.col("effdate") <= F.col("pdate"))
    if fx_rec:
        # exclude corrections recorded AFTER the payment's own date
        cond = cond & (F.col("recdate") <= F.col("pdate"))

    j = pay.join(fx, cond, "left")

    if fx_rec:
        order = [F.col("effdate").desc_nulls_last(), F.col("recstr").desc_nulls_last()]
    elif fx_ver:
        order = [F.col("effdate").desc_nulls_last(), F.col("ver").asc_nulls_last()]
    else:
        order = [F.col("effdate").desc_nulls_last()]

    w = Window.partitionBy("_pid").orderBy(*order)
    ranked = j.withColumn("_rn", F.row_number().over(w)).where(F.col("_rn") == 1)

    usd = F.when(F.col("ccy") == F.lit("USD"), F.col("amount")) \
           .otherwise(F.col("amount") * F.col("rate"))
    ranked = ranked.withColumn("usd_amount", usd)

    return (ranked
            .groupBy(F.col("pdate").alias("settlement_date"))
            .agg(F.sum("usd_amount").alias("usd_total")))

