def _force_string(schema, cols):
    if schema is None:
        return None
    fields = []
    for f in schema.fields:
        if f.name in cols:
            fields.append(StructField(f.name, StringType(), True))
        else:
            fields.append(f)
    return StructType(fields)


_pay_schema_s = _force_string(_pay_schema, {PAY_DT})
_fx_force = {FX_EFF} | ({FX_REC} if FX_REC else set())
_fx_schema_s = _force_string(_fx_schema, _fx_force)


def _day(colname):
    # UTC calendar day from an ISO string / date / timestamp rendered as text
    return F.to_date(F.substring(F.col(colname).cast("string"), 1, 10))


@dp.materialized_view(name="payments_src")
