    cols = [
        F.col(FX_CUR).cast("string").alias("currency"),
        F.col(FX_RATE).cast("double").alias("rate"),
        _day(FX_EFF).alias("eff_dt"),
    ]
    if FX_REC:
        cols.append(_day(FX_REC).alias("rec_dt"))
    else:
        cols.append(_day(FX_EFF).alias("rec_dt"))
    return df.select(*cols)


@dp.materialized_view(name="usd_daily")
def usd_daily():
    spark = SparkSession.active()
    p = spark.read.table("spark_catalog.default.payments_src")
    r = spark.read.table("spark_catalog.default.fx_rates_src")

    j = p.join(r, on="currency", how="inner")
    # valid-time: rate effective on or before the payment's own day
    j = j.where(F.col("eff_dt") <= F.col("settlement_date"))
    # system-time: only versions known as of the payment's own day (exclude later corrections)
    j = j.where(F.col("rec_dt").isNull() | (F.col("rec_dt") <= F.col("settlement_date")))

    rec_ord = F.coalesce(F.col("rec_dt"), F.to_date(F.lit("1900-01-01")))
    picked = j.groupBy("pid", "settlement_date", "amount").agg(
        F.max(
            F.struct(
                F.col("eff_dt").alias("e"),
                rec_ord.alias("r"),
                F.col("rate").alias("v"),
            )
        ).alias("m")
    )
    picked = picked.withColumn("usd", F.col("amount") * F.col("m")["v"])

    res = picked.groupBy("settlement_date").agg(F.sum("usd").alias("usd_total"))
    return res.select(F.col("settlement_date"), F.col("usd_total"))

