        dt = _spark().read.json(path).dtypes
        return [n for n, _ in dt], {n: t for n, t in dt}
    except Exception:
        return [], {}


def _pick(names, used, exacts, tokens):
    low = {n.lower(): n for n in names}
    for e in exacts:
        k = e.lower()
        if k in low and low[k] not in used:
            used.add(low[k]); return low[k]
    for t in tokens:
        for n in names:
            if t in n.lower() and n not in used:
                used.add(n); return n
    return None


def _d(x):
    # date portion (UTC calendar day for ISO 'Z' timestamps) regardless of source type
    return F.to_date(F.substring(F.col(x).cast("string"), 1, 10))


# ---- resolve payments schema ----
_pn, _pt = _schema(PAY_PATH)
_pu = set()
PAY_CCY  = _pick(_pn, _pu, ["currency", "ccy", "currency_code", "curr"], ["curren", "ccy"])
