        _d(FX_VALID).alias("f_valid_date"),
        F.col(FX_RATE).cast("double").alias("f_rate"),
    ]
    if FX_TXN is None:
        cols.append(F.lit(0.0).alias("f_txn_ord"))
        cols.append(F.lit(None).cast("date").alias("f_txn_date"))
    elif VERSION_MODE:
        cols.append(F.col(FX_TXN).cast("double").alias("f_txn_ord"))
        cols.append(F.lit(None).cast("date").alias("f_txn_date"))
    else:
        cols.append(F.col(FX_TXN).cast("string").alias("f_txn_ord"))
        cols.append(_d(FX_TXN).alias("f_txn_date"))
    return df.select(*cols)


@dp.materialized_view(name="usd_daily")
def usd_daily():
    p = _spark().read.table("spark_catalog.default.payments_src")
    f = _spark().read.table("spark_catalog.default.fx_src")

    # SCD2 as-of on valid time; exclude corrections recorded AFTER the payment's own date
    cond = (F.col("p_ccy") == F.col("f_ccy")) & (F.col("f_valid_date") <= F.col("settlement_date"))
    if not VERSION_MODE and FX_TXN is not None:
        cond = cond & (F.col("f_txn_date").isNull() | (F.col("f_txn_date") <= F.col("settlement_date")))

    j = p.join(f, cond, "left")

    if VERSION_MODE or FX_TXN is None:
        # no transaction time available: original version (earliest) is the one in effect then
        order = [F.col("f_valid_date").desc_nulls_last(), F.col("f_txn_ord").asc_nulls_last()]
    else:
        # latest version recorded on/before the payment date
        order = [F.col("f_valid_date").desc_nulls_last(), F.col("f_txn_ord").desc_nulls_last()]

    w = Window.partitionBy("p_id").orderBy(*order)
    ranked = j.withColumn("_rn", F.row_number().over(w)).where(F.col("_rn") == 1)

    valued = ranked.withColumn("usd", F.col("p_amount") * F.col("f_rate"))
    return valued.groupBy("settlement_date").agg(F.sum("usd").alias("usd_total"))

