                 "updated", "update", "load", "observed", "change", "_ts", "_at"]
FX_CAPTURE = _pick([c for c in _fx_cols if c != FX_BUSINESS], _cap_exact, _cap_contains)
FX_CAPTURE_IS_DATE = bool(FX_CAPTURE) and ("date" in FX_CAPTURE.lower())

FX_OP = _pick(_fx_cols, ["op", "operation", "cdc_op", "change_type", "_op", "action", "optype", "op_type"])


def _to_utc_date(colname, is_date):
    c = F.col(colname)
    if is_date:
        return F.coalesce(F.to_date(c), F.to_date(F.substring(c.cast("string"), 1, 10)))
    ts = F.to_timestamp(c)
    epoch_day = F.date_from_unix_date(F.floor(F.unix_timestamp(ts) / F.lit(86400)).cast("int"))
    return F.coalesce(epoch_day, F.to_date(c), F.to_date(F.substring(c.cast("string"), 1, 10)))


@dp.materialized_view(name="payments_raw")
def payments_raw():
    return SparkSession.active().read.json(PAYMENTS_PATH)


@dp.materialized_view(name="fx_rates_raw")
def fx_rates_raw():
    return SparkSession.active().read.json(FX_PATH)


@dp.materialized_view(name="usd_daily")
def usd_daily():
    spark = SparkSession.active()
    p = spark.read.table("spark_catalog.default.payments_raw")
    r = spark.read.table("spark_catalog.default.fx_rates_raw")

    p = p.select(
        F.upper(F.col(PAY_CCY)).alias("_ccy"),
        F.col(PAY_AMT).cast("double").alias("_amt"),
        _to_utc_date(PAY_DATE_FIELD, PAY_DATE_IS_DATE).alias("_sdate"),
    ).withColumn("_pid", F.monotonically_increasing_id())

    if FX_OP:
        r = r.filter(~F.upper(F.col(FX_OP).cast("string")).isin("D", "DELETE", "REMOVE", "DEL"))

    cap_expr = _to_utc_date(FX_CAPTURE, FX_CAPTURE_IS_DATE) if FX_CAPTURE else _to_utc_date(FX_BUSINESS, True)
    r = r.select(
        F.upper(F.col(FX_CCY)).alias("_ccy"),
        F.col(FX_RATE).cast("double").alias("_rate"),
        _to_utc_date(FX_BUSINESS, True).alias("_bdate"),
        cap_expr.alias("_cdate"),
    )

    # Bitemporal as-of: rate effective on/before payment date, and known (not a later
    # correction) on/before the payment's own date. Pick latest effective, then latest known.
    joined = p.join(r, on="_ccy", how="left").filter(
        (F.col("_bdate") <= F.col("_sdate")) & (F.col("_cdate") <= F.col("_sdate"))
    )
    w = Window.partitionBy("_pid").orderBy(
        F.col("_bdate").desc(), F.col("_cdate").desc(), F.col("_rate").desc()
    )
    picked = (
        joined.withColumn("_rn", F.row_number().over(w))
        .filter(F.col("_rn") == 1)
        .select("_pid", "_rate")
    )

    out = p.join(picked, on="_pid", how="left")
    out = out.withColumn(
        "_eff", F.when(F.col("_ccy") == "USD", F.lit(1.0)).otherwise(F.col("_rate"))
    ).filter(F.col("_eff").isNotNull())
    out = out.withColumn("_usd", F.col("_amt") * F.col("_eff"))

    result = (
        out.groupBy(F.col("_sdate").alias("settlement_date"))
        .agg(F.sum("_usd").alias("usd_total"))
    )
    return result.select(F.col("settlement_date").cast("date"), F.col("usd_total").cast("double"))

import os
from pyspark.sql import SparkSession, functions as F, Window


def _pick_order_col(cols):
    # priority list of plausible monotonic ordering columns in a CDC feed
    candidates = [
        "seq", "sequence", "seq_no", "seqno", "offset", "log_offset",
        "change_seq", "event_seq", "commit_seq", "lsn", "scn", "version",
        "ver", "op_ts", "ts", "timestamp", "event_ts", "event_time",
        "change_ts", "updated_at", "_ts", "op_time",
    ]
    lower = {c.lower(): c for c in cols}
    for cand in candidates:
        if cand in lower:
            return lower[cand]
    return None


def main():
    spark = (
        SparkSession.builder
        .appName("new_cdc_tombstone")
        .getOrCreate()
    )
    spark.sparkContext.setLogLevel("WARN")

    default_input = (
        "/home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/"
        ".work.powered.AB.n12.part2/_data/gen_customers_cdc_seed8675.ndjson"
    )
    input_path = os.environ.get("AGENT_INPUT_PATH", default_input)

    out_path = os.environ.get("AGENT_OUTPUT_PATH")
    out_table = os.environ.get("AGENT_OUTPUT_TABLE")

    raw = spark.read.json(input_path)
    cols = raw.columns

    # --- Locate the customer key ---
    key_col = None
    for cand in ["customer_id", "customerId", "id", "cust_id"]:
        for c in cols:
            if c.lower() == cand.lower():
                key_col = c
                break
        if key_col:
            break
    if key_col is None:
        raise ValueError(f"Could not find customer key column in: {cols}")

    df = raw
    if key_col != "customer_id":
        df = df.withColumnRenamed(key_col, "customer_id")

    # --- Locate tier/region columns (payload attributes) ---
    def find_col(name):
        for c in df.columns:
            if c.lower() == name:
                return c
        return None

    tier_src = find_col("tier")
    region_src = find_col("region")

    # normalize: treat empty/whitespace strings as NULL so tombstones (empty
    # records) become all-null payloads.
    def norm(src):
        if src is None:
            return F.lit(None).cast("string")
        col = F.col(src).cast("string")
        return F.when(F.trim(col) == "", F.lit(None)).otherwise(col)

    df = df.withColumn("_tier", norm(tier_src))
    df = df.withColumn("_region", norm(region_src))

    # --- Deterministic ordering to select the LATEST event per customer ---
    order_col = _pick_order_col(df.columns)
    if order_col is None:
        # Fallback: preserve file arrival order (deterministic for a single
        # re-read of the same immutable input).
        df = df.withColumn("_ord", F.monotonically_increasing_id())
        order_expr = F.col("_ord")
    else:
        # order numerically when possible, else lexically; tie-break stably.
        order_expr = F.col(order_col)

    # Stable tie-breaker to guarantee reproducible pick when ordering ties.
    df = df.withColumn("_rid", F.monotonically_increasing_id())

    w = Window.partitionBy("customer_id").orderBy(
        order_expr.asc_nulls_first(), F.col("_rid").asc()
    )
    df = df.withColumn("_rn_desc", F.row_number().over(
        Window.partitionBy("customer_id").orderBy(
            order_expr.desc_nulls_last(), F.col("_rid").desc()
        )
    ))

    latest = df.filter(F.col("_rn_desc") == 1)

    # A deletion tombstone = latest event carries an empty payload
    # (both attributes null after normalization).
    is_tombstone = F.col("_tier").isNull() & F.col("_region").isNull()

    survivors = latest.filter(~is_tombstone)

    result = (
        survivors
        .select(
            F.col("customer_id"),
            F.col("_tier").alias("tier"),
            F.col("_region").alias("region"),
        )
    )

    # Register the contract-named temp view in this session.
    result.createOrReplaceTempView("customers_current")

    if out_path:
        result.write.mode("overwrite").parquet(out_path)
    elif out_table:
        result.write.mode("overwrite").saveAsTable(out_table)
    else:
        # local default
        result.write.mode("overwrite").parquet(
            os.path.join(os.getcwd(), "customers_current.parquet")
        )

    print("Run is COMPLETED")
    spark.stop()


if __name__ == "__main__":
    main()

