from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F, Window

TRADES_PATH = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_trades_seed8675.ndjson"
FX_PATH     = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.powered.AB.n12.part2/_data/gen_fx_rates_cdc_seed8675.ndjson"


def _pick(cols, cands):
    low = {c.lower(): c for c in cols}
    for x in cands:
        if x in low:
            return low[x]
    for x in cands:
        for c in cols:
            if x in c.lower():
                return c
    return None


def _cols(path):
    try:
        return SparkSession.active().read.json(path).columns
    except Exception:
        return []


_tc = _cols(TRADES_PATH)
_fc = _cols(FX_PATH)

T_ID  = _pick(_tc, ["trade_id", "tradeid", "id"]) or "trade_id"
T_CCY = _pick(_tc, ["currency", "ccy", "curr"]) or "currency"
T_AMT = _pick(_tc, ["amount", "notional", "qty", "quantity", "value"]) or "amount"
T_TS  = _pick(_tc, ["trade_time", "traded_at", "trade_ts", "event_time",
                    "event_ts", "timestamp", "ts", "time"]) or "trade_time"

F_CCY  = _pick(_fc, ["currency", "ccy", "curr"]) or "currency"
F_RATE = _pick(_fc, ["rate", "fx_rate", "usd_rate", "px", "price"]) or "rate"
F_FROM = _pick(_fc, ["valid_from", "effective_from", "effective_time", "effective_ts",
                     "valid_ts", "from_ts", "start_ts", "start", "asof", "as_of",
                     "timestamp", "ts", "time"]) or "valid_from"
F_SEQ  = _pick(_fc, ["seq", "seq_num", "seqnum", "sequence", "version", "rev",
                     "change_seq", "update_seq", "commit_seq", "offset", "_seq",
                     "ingest_seq"])


def _ts(name):
    c = F.col(name)
    return F.coalesce(F.to_timestamp(c), c.cast("timestamp"))


@dp.materialized_view(name="rate_dim")
def rate_dim():
    df = SparkSession.active().read.json(FX_PATH)
    seq_col = F.col(F_SEQ).cast("long") if F_SEQ else F.lit(0).cast("long")
    df = df.select(
        F.upper(F.col(F_CCY)).alias("currency"),
        F.col(F_RATE).cast("double").alias("rate"),
        _ts(F_FROM).alias("valid_from"),
        seq_col.alias("_seq"),
    )
    # collapse CDC corrections: latest version wins for a given effective instant
    w = Window.partitionBy("currency", "valid_from").orderBy(
        F.col("_seq").desc(), F.col("rate").desc()
    )
    df = df.withColumn("_rn", F.row_number().over(w)).where(F.col("_rn") == 1)
    # build non-overlapping validity intervals [valid_from, next valid_from)
    w2 = Window.partitionBy("currency").orderBy("valid_from")
    df = df.withColumn("valid_to", F.lead("valid_from").over(w2))
    return df.select("currency", "rate", "valid_from", "valid_to")


@dp.materialized_view(name="gold_trades")
def gold_trades():
    s = SparkSession.active()
    t = (
        s.read.json(TRADES_PATH)
        .withColumn("_ccy", F.upper(F.col(T_CCY)))
        .withColumn("_tt", _ts(T_TS))
    )
    r = s.read.table("spark_catalog.default.rate_dim").select(
        F.col("currency").alias("_r_ccy"),
        F.col("rate").alias("_r_rate"),
        F.col("valid_from").alias("_r_from"),
        F.col("valid_to").alias("_r_to"),
    )
    cond = (
        (F.col("_ccy") == F.col("_r_ccy"))
        & (F.col("_tt") >= F.col("_r_from"))
        & (F.col("_r_to").isNull() | (F.col("_tt") < F.col("_r_to")))
    )
    j = t.join(r, cond, "left")
    rate = F.when(F.col("_ccy") == F.lit("USD"), F.lit(1.0)).otherwise(F.col("_r_rate"))
    out = j.withColumn("amount_usd", F.col(T_AMT).cast("double") * rate)
    return out.drop("_r_ccy", "_r_rate", "_r_from", "_r_to", "_ccy", "_tt")


@dp.materialized_view(name="mart_positions")
def mart_positions():
    g = SparkSession.active().read.table("spark_catalog.default.gold_trades")
    return (
        g.groupBy(F.col(T_CCY).alias("currency"))
        .agg(F.sum("amount_usd").alias("position_usd"))
    )
